// vault.mjs — Vault I/O helpers for the learning web app

import { join } from 'path';
import { readFile, writeFile } from 'fs/promises';
import { readNote, readFolder } from '../../lib/frontmatter.mjs';
import { getLearningRoot } from '../../lib/config.mjs';

// Re-export for convenience
export { readNote, readFolder };

/**
 * parseInlineFields(content)
 * Extracts all `key:: value` lines from markdown body text.
 * Returns a plain object with auto-typed values.
 */
export function parseInlineFields(content) {
  const result = {};
  const lines = content.split('\n');
  const pattern = /^([a-zA-Z_][a-zA-Z0-9_]*)::[ \t]*(.*)$/;

  for (const line of lines) {
    const match = line.match(pattern);
    if (!match) continue;

    const key = match[1].trim();
    const raw = match[2].trim();

    result[key] = autoType(raw);
  }

  return result;
}

function autoType(raw) {
  // Empty array literal
  if (raw === '[]') return [];

  // JSON array
  if (raw.startsWith('[') && raw.endsWith(']')) {
    try {
      return JSON.parse(raw);
    } catch {
      return raw;
    }
  }

  // Number
  if (raw !== '' && !isNaN(Number(raw))) {
    return Number(raw);
  }

  return raw;
}

/**
 * serializeMastery(rawText, updates)
 * Replaces key:: value lines in-place for each key in updates.
 * If a key doesn't exist, appends before the first ## heading.
 * Returns new file text.
 */
export function serializeMastery(rawText, updates) {
  let text = rawText;
  const handled = new Set();

  for (const [key, value] of Object.entries(updates)) {
    const serialized = serializeValue(value);
    const pattern = new RegExp(`^(${escapeRegex(key)}::[ \\t]*)(.*)$`, 'm');

    if (pattern.test(text)) {
      text = text.replace(pattern, `${key}:: ${serialized}`);
      handled.add(key);
    }
  }

  // Keys not yet written — append before first ## heading
  const missing = Object.entries(updates).filter(([k]) => !handled.has(k));
  if (missing.length > 0) {
    const headingMatch = text.match(/^## /m);
    const insertLines = missing.map(([k, v]) => `${k}:: ${serializeValue(v)}`).join('\n');

    if (headingMatch) {
      const idx = text.indexOf(headingMatch[0]);
      text = text.slice(0, idx) + insertLines + '\n' + text.slice(idx);
    } else {
      text = text.trimEnd() + '\n' + insertLines + '\n';
    }
  }

  return text;
}

function serializeValue(value) {
  if (Array.isArray(value)) return JSON.stringify(value);
  return String(value);
}

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * appendCheckHistory(rawText, entry)
 * Finds check_history:: line and appends entry object {date, mode, result, response_text}.
 * Stores as JSON-serialized array string.
 * Returns new file text.
 */
export function appendCheckHistory(rawText, entry) {
  const pattern = /^check_history::[ \t]*(.*)$/m;
  const match = rawText.match(pattern);

  let history = [];
  if (match) {
    const raw = match[1].trim();
    if (raw && raw !== '[]') {
      try {
        history = JSON.parse(raw);
      } catch {
        history = [];
      }
    }
  }

  history.push(entry);
  const serialized = JSON.stringify(history);

  if (match) {
    return rawText.replace(pattern, `check_history:: ${serialized}`);
  }

  // No existing line — append before first ## heading
  return serializeMastery(rawText, { check_history: history });
}

/**
 * getLearningPaths()
 * Returns an object with all learning folder paths.
 */
export function getLearningPaths() {
  const root = getLearningRoot();
  return {
    root,
    domains: join(root, '01_Domains'),
    nodes: join(root, '02_Nodes'),
    sessions: join(root, '04_Sessions'),
    mastery: join(root, '05_Mastery'),
    projects: join(root, '07_Projects'),
    reviews: join(root, '08_Reviews'),
    resources: join(root, '09_Resources'),
    notebooks: join(root, 'Learner_Notebooks'),
  };
}

