// search.mjs — Full-text search module for the learning web app

import { readdir, readFile, stat } from 'fs/promises';
import { join, relative, basename, extname } from 'path';
import { parseInlineFields } from './vault.mjs';
import { readNote } from '../../lib/frontmatter.mjs';

/**
 * buildIndex(root)
 * Recursively reads all .md files under root.
 * Returns array of { path, filename, title, content, data, snippet }.
 */
export async function buildIndex(root) {
  const files = await collectMdFiles(root);
  const entries = await Promise.all(files.map(f => indexFile(root, f)));
  return entries.filter(Boolean);
}

async function collectMdFiles(dir) {
  const results = [];
  let entries;
  try {
    entries = await readdir(dir, { withFileTypes: true });
  } catch {
    return results;
  }

  for (const entry of entries) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      const sub = await collectMdFiles(full);
      results.push(...sub);
    } else if (entry.isFile() && extname(entry.name) === '.md') {
      results.push(full);
    }
  }
  return results;
}

async function indexFile(root, filePath) {
  try {
    const raw = await readFile(filePath, 'utf8');
    const { data, content } = parseNote(raw);
    const title = extractTitle(content, basename(filePath, '.md'));
    const snippet = content.replace(/^#.*$/mg, '').trim().slice(0, 200);

    return {
      path: relative(root, filePath).replace(/\\/g, '/'),
      filename: basename(filePath),
      title,
      content,
      data,
      snippet,
    };
  } catch {
    return null;
  }
}

function parseNote(raw) {
  const fmMatch = raw.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
  if (!fmMatch) return { data: {}, content: raw };

  const yamlBlock = fmMatch[1];
  const content = fmMatch[2];
  const data = parseSimpleYaml(yamlBlock);
  return { data, content };
}

function parseSimpleYaml(yaml) {
  const result = {};
  const lines = yaml.split('\n');
  let currentKey = null;
  let currentArray = null;

  for (const line of lines) {
    const arrayItem = line.match(/^  - (.+)$/);
    if (arrayItem && currentArray !== null) {
      currentArray.push(arrayItem[1].trim());
      continue;
    }

    const kv = line.match(/^([a-zA-Z_][a-zA-Z0-9_]*):\s*(.*)$/);
    if (kv) {
      currentKey = kv[1];
      const val = kv[2].trim();
      if (val === '' || val === '[]') {
        currentArray = val === '[]' ? [] : null;
        result[currentKey] = currentArray ?? '';
      } else {
        currentArray = null;
        result[currentKey] = val.replace(/^["']|["']$/g, '');
      }
    }
  }

  return result;
}

function extractTitle(content, fallback) {
  const h1 = content.match(/^# (.+)$/m);
  return h1 ? h1[1].trim() : fallback;
}

/**
 * search(index, query, filters)
 * Filters by domain, tag, note_type, folder.
 * Scores: +3 title match, +1 per body match.
 * Returns top 20 results.
 */
export function search(index, query, filters = {}) {
  const q = (query || '').toLowerCase().trim();
  const terms = q ? q.split(/\s+/) : [];

  let results = index;

  // Apply filters
  if (filters.domain) {
    const d = filters.domain.toLowerCase();
    results = results.filter(
      r =>
        (r.data.domain || '').toLowerCase() === d ||
        (r.data.primary_domain || '').toLowerCase() === d
    );
  }

  if (filters.tag) {
    const t = filters.tag.toLowerCase();
    results = results.filter(r => {
      const tags = Array.isArray(r.data.tags)
        ? r.data.tags
        : String(r.data.tags || '').split(',');
      return tags.some(tag => tag.toLowerCase().includes(t));
    });
  }

  if (filters.note_type) {
    const nt = filters.note_type.toLowerCase();
    results = results.filter(
      r =>
        (r.data.template || '').toLowerCase().includes(nt) ||
        (r.data.node_type || '').toLowerCase().includes(nt)
    );
  }

  if (filters.folder) {
    const f = filters.folder.toLowerCase();
    results = results.filter(r => r.path.toLowerCase().startsWith(f));
  }

  if (terms.length === 0) {
    return results.slice(0, 20).map(r => toResult(r, 0));
  }

  // Score
  const scored = results
    .map(r => {
      let score = 0;
      const titleLower = r.title.toLowerCase();
      const bodyLower = r.content.toLowerCase();

      for (const term of terms) {
        if (titleLower.includes(term)) score += 3;
        // Count body occurrences
        let pos = 0;
        while ((pos = bodyLower.indexOf(term, pos)) !== -1) {
          score += 1;
          pos += term.length;
        }
      }

      return { entry: r, score };
    })
    .filter(x => x.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 20);

  return scored.map(({ entry, score }) => toResult(entry, score));
}

function toResult(r, score) {
  return {
    path: r.path,
    filename: r.filename,
    title: r.title,
    snippet: r.snippet,
    score,
    domain: r.data.domain || r.data.primary_domain || '',
    tags: r.data.tags || [],
  };
}

/**
 * getNote(root, relativePath)
 * Reads a single note by relative path from root.
 * Returns { path, data, content, inlineFields }.
 */
export async function getNote(root, relativePath) {
  const fullPath = join(root, relativePath);
  const raw = await readFile(fullPath, 'utf8');
  const { data, content } = parseNote(raw);
  const inlineFields = parseInlineFields(content);

  return {
    path: relativePath.replace(/\\/g, '/'),
    data,
    content,
    inlineFields,
  };
}

