    const kv = line.match(/^([a-zA-Z_][a-zA-Z0-9_]*):\s*(.*)$/);
    if (kv) {
      currentKey = kv[1];
      const val = kv[2].trim();
      if (val === '' || val === '[]') {
        currentArray = val === '[]' ? [] : null;
        result[currentKey] = currentArray ?? '';
      } else {
        currentArray = null;
        result[currentKey] = val.replace(/^["']|["']$/g, '');
      }
    }
  }

  return result;
}

function extractTitle(content, fallback) {
  const h1 = content.match(/^# (.+)$/m);
  return h1 ? h1[1].trim() : fallback;
}

/**
 * search(index, query, filters)
 * Filters by domain, tag, note_type, folder.
 * Scores: +3 title match, +1 per body match.
 * Returns top 20 results.
 */
export function search(index, query, filters = {}) {
  const q = (query || '').toLowerCase().trim();
  const terms = q ? q.split(/\s+/) : [];

  let results = index;

  // Apply filters
  if (filters.domain) {
    const d = filters.domain.toLowerCase();
    results = results.filter(
      r =>
        (r.data.domain || '').toLowerCase() === d ||
        (r.data.primary_domain || '').toLowerCase() === d
    );
  }

  if (filters.tag) {
    const t = filters.tag.toLowerCase();
    results = results.filter(r => {
      const tags = Array.isArray(r.data.tags)
        ? r.data.tags
        : String(r.data.tags || '').split(',');
      return tags.some(tag => tag.toLowerCase().includes(t));
    });
  }

  if (filters.note_type) {
    const nt = filters.note_type.toLowerCase();
    results = results.filter(
      r =>
        (r.data.template || '').toLowerCase().includes(nt) ||
        (r.data.node_type || '').toLowerCase().includes(nt)
    );
  }

  if (filters.folder) {
    const f = filters.folder.toLowerCase();
    results = results.filter(r => r.path.toLowerCase().startsWith(f));
  }

  if (terms.length === 0) {
    return results.slice(0, 20).map(r => toResult(r, 0));
  }

  // Score
  const scored = results
    .map(r => {
      let score = 0;
      const titleLower = r.title.toLowerCase();
      const bodyLower = r.content.toLowerCase();

      for (const term of terms) {
        if (titleLower.includes(term)) score += 3;
        // Count body occurrences
        let pos = 0;
        while ((pos = bodyLower.indexOf(term, pos)) !== -1) {
          score += 1;
          pos += term.length;
        }
      }

      return { entry: r, score };
    })
    .filter(x => x.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 20);

  return scored.map(({ entry, score }) => toResult(entry, score));
}

function toResult(r, score) {
  return {
    path: r.path,
    filename: r.filename,
    title: r.title,
    snippet: r.snippet,
    score,
    domain: r.data.domain || r.data.primary_domain || '',
    tags: r.data.tags || [],
  };
}

/**
 * getNote(root, relativePath)
 * Reads a single note by relative path from root.
 * Returns { path, data, content, inlineFields }.
 */
export async function getNote(root, relativePath) {
  const fullPath = join(root, relativePath);
  const raw = await readFile(fullPath, 'utf8');
  const { data, content } = parseNote(raw);
  const inlineFields = parseInlineFields(content);

  return {
    path: relativePath.replace(/\\/g, '/'),
    data,
    content,
    inlineFields,
  };
}

