/**
 * unlock.mjs — Mastery state evaluation for the learning web app.
 * Pure logic module: no filesystem, no HTTP, no side effects.
 */

// Minimum confidence required to advance FROM level N (index = current level)
const LEVEL_THRESHOLDS = [0, 20, 40, 60, 80, 95];

// check_type eligibility for level advancement
// Surface checks may advance levels 0→1 and 1→2 (i.e., current level 0 or 1)
// Advanced checks may advance levels 2→3, 3→4, 4→5 (i.e., current level 2, 3, or 4)
const SURFACE_ELIGIBLE_LEVELS = new Set([0, 1]);
const ADVANCED_ELIGIBLE_LEVELS = new Set([2, 3, 4]);

/**
 * Return today's ISO date string (YYYY-MM-DD).
 */
function todayISO() {
  return new Date().toISOString().slice(0, 10);
}

/**
 * Clamp a number between min and max (inclusive).
 */
function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

/**
 * Parse a JSON array string safely, returning a default on failure.
 */
function parseJSONArray(raw, fallback = []) {
  if (!raw || raw === '[]' || raw === '') return fallback;
  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : fallback;
  } catch {
    return fallback;
  }
}

/**
 * Compute stability string from check history and level.
 *
 * Rules:
 *   fragile  — level < 2 OR fewer than 3 total checks
 *   building — 3+ checks, no two consecutive fails
 *   solid    — level >= 3 AND last 3 checks all passed
 *   mastered — level === 5 AND stability would otherwise be solid
 *
 * @param {number} level
 * @param {object[]} history  - array of { result: 'pass'|'fail', ... }
 * @returns {string}
 */
export function computeStability(level, history) {
  if (level < 2 || history.length < 3) {
    return 'fragile';
  }

  // Check for two consecutive fails anywhere in history
  let hasConsecutiveFails = false;
  for (let i = 1; i < history.length; i++) {
    if (history[i].result === 'fail' && history[i - 1].result === 'fail') {
      hasConsecutiveFails = true;
      break;
    }
  }

  const lastThree = history.slice(-3);
  const lastThreeAllPass = lastThree.every(h => h.result === 'pass');

  if (level === 5 && lastThreeAllPass) {
    return 'mastered';
  }

  if (level >= 3 && lastThreeAllPass) {
    return 'solid';
  }

  if (!hasConsecutiveFails) {
    return 'building';
  }

  // Has consecutive fails — demote to fragile regardless of level/count
  return 'fragile';
}

/**
 * Check if all prerequisites for a topic are met.
 *
 * @param {string} prerequisitesField  - raw "none" or "topic-a,topic-b"
 * @param {object[]} prereqStates      - [ { topic_id, level } ]
 * @param {number} threshold           - minimum level required (default 1)
 * @returns {boolean}
 */
export function prerequisitesMet(prerequisitesField, prereqStates, threshold = 1) {
  const raw = (prerequisitesField || '').trim();
  if (!raw || raw === 'none') return true;

  const required = raw.split(',').map(s => s.trim()).filter(Boolean);
  if (required.length === 0) return true;

  const stateMap = new Map(prereqStates.map(s => [s.topic_id, s]));

  return required.every(topicId => {
    const state = stateMap.get(topicId);
    return state !== undefined && state.level >= threshold;
  });
}

/**
 * Determine whether a level advance is earned.
 *
 * @param {number} currentLevel
 * @param {string} result        - 'pass'|'fail'
 * @param {string} check_type    - 'surface'|'advanced'
 * @param {number} newConfidence - confidence AFTER applying delta
 * @returns {boolean}
 */
function shouldAdvanceLevel(currentLevel, result, check_type, newConfidence) {
  if (result !== 'pass') return false;
  if (currentLevel >= 5) return false;

  const threshold = LEVEL_THRESHOLDS[currentLevel];
  if (newConfidence < threshold) return false;

  if (check_type === 'surface' && SURFACE_ELIGIBLE_LEVELS.has(currentLevel)) return true;
  if (check_type === 'advanced' && ADVANCED_ELIGIBLE_LEVELS.has(currentLevel)) return true;

  return false;
}

/**
 * Build a next_action string from the new mastery state.
 *
 * @param {string} stability
 * @param {string} progress_state
 * @param {number} level
 * @param {string} existingNextAction
 * @returns {string}
 */
function buildNextAction(stability, progress_state, level, existingNextAction) {
  if (progress_state === 'complete') {
    return 'Review periodically to maintain mastery.';
  }
  if (progress_state === 'locked') {
    return 'Complete prerequisites before continuing.';
  }
  if (stability === 'mastered') {
    return 'Mastered — teach it to someone else or apply in a new domain.';
  }
  if (stability === 'solid') {
    return `Solid at level ${level}. Attempt advanced synthesis checks to push further.`;
  }
  if (stability === 'building') {
    return existingNextAction || `Keep practicing — you are building toward level ${level + 1}.`;
  }
  // fragile
  if (level === 0) {
    return existingNextAction || 'Begin with a recall check to establish baseline understanding.';
  }
  return existingNextAction || `Strengthen foundations at level ${level} before advancing.`;
}

/**
 * Evaluate a checkpoint submission and compute new mastery state.
 *
 * @param {object} currentFields   - parsed inline fields from mastery note
 * @param {object} submission      - { result: 'pass'|'fail', check_type: 'surface'|'advanced', confidence_delta: number, notes: string }
 * @param {object[]} prereqStates  - array of { topic_id, level, progress_state } for all prerequisite areas
 * @returns {{ new_level, new_stability, new_confidence, new_progress_state, unlocked_topic_ids: string[], next_action: string }}
 */
export function evaluateUnlock(currentFields, submission, prereqStates = []) {
  // --- 1. Parse current state (never mutate input) ---
  const currentLevel = Number(currentFields.level ?? 0);
  const currentConfidence = Number(currentFields.confidence ?? 0);
  const currentProgressState = currentFields.progress_state ?? 'active';
  const prerequisitesField = currentFields.prerequisites ?? 'none';
  const existingNextAction = currentFields.next_action ?? '';

  const rawHistory = currentFields.check_history ?? '[]';
  const history = parseJSONArray(rawHistory, []);

  // --- 2. Add new history entry ---
  const newEntry = {
    date: todayISO(),
    result: submission.result,
    check_type: submission.check_type,
    notes: submission.notes ?? '',
  };
  const updatedHistory = [...history, newEntry];

  // --- 3. Compute new confidence ---
  const newConfidence = clamp(currentConfidence + (submission.confidence_delta ?? 0), 0, 100);

  // --- 4. Determine level advancement ---
  const advanceLevel = shouldAdvanceLevel(
    currentLevel,
    submission.result,
    submission.check_type,
    newConfidence
  );
  const newLevel = advanceLevel ? currentLevel + 1 : currentLevel;

  // --- 5. Compute new stability ---
  const newStability = computeStability(newLevel, updatedHistory);

  // --- 6. Determine new progress_state ---
  let newProgressState = currentProgressState;

  if (currentProgressState === 'locked') {
    const prereqThreshold = Number(currentFields.unlock_threshold ?? 1);
    const met = prerequisitesMet(prerequisitesField, prereqStates, prereqThreshold);
    if (met) {
      newProgressState = 'active';
    }
    // If still locked, skip the complete check
  }

  if (newProgressState === 'active') {
    const qualifiesComplete =
      newLevel >= 4 && (newStability === 'solid' || newStability === 'mastered');
    if (qualifiesComplete) {
      newProgressState = 'complete';
    }
  }
  // Never transition backwards automatically

  // --- 7. Detect newly unlocked topics ---
  // For each prereqState that was locked, check if this evaluation changes things.
  // The caller passes ALL prereqStates. We return topic_ids of topics that:
  //   - currently have progress_state === 'locked'
  //   - and whose prerequisites are now met given the updated level of THIS topic
  //
  // We only know about THIS topic's new level. Unlocking logic for OTHER topics
  // depends on the caller providing their prerequisite info. We check each locked
  // prereqState to see if their prerequisites include this topic and whether the
  // new level satisfies the threshold.
  const unlockedTopicIds = [];
  const thisTopicId = currentFields.topic_id ?? '';

  for (const state of prereqStates) {
    if (state.progress_state !== 'locked') continue;
    // We don't have the full prereq fields for other topics here,
    // but the caller may pass states with a `prerequisites` field included.
    // Support both: state.prerequisites (full string) or infer from this topic only.
    if (state.prerequisites !== undefined) {
      const updatedStates = prereqStates.map(s =>
        s.topic_id === thisTopicId ? { ...s, level: newLevel } : s
      );
      const met = prerequisitesMet(state.prerequisites, updatedStates, 1);
      if (met) {
        unlockedTopicIds.push(state.topic_id);
      }
    }
  }

  // --- 8. Build next_action ---
  const nextAction = buildNextAction(newStability, newProgressState, newLevel, existingNextAction);

  return {
    new_level: newLevel,
    new_stability: newStability,
    new_confidence: newConfidence,
    new_progress_state: newProgressState,
    unlocked_topic_ids: unlockedTopicIds,
    next_action: nextAction,
  };
}

