/**
 * checks.mjs — Knowledge check prompt generator for the learning web app.
 * Pure logic module: no filesystem, no HTTP, no LLM calls.
 * Prompts are derived from mastery note inline fields only.
 */

/**
 * Convert a topic_id slug into a readable label.
 * e.g. "fundamentals-unit-economics" → "unit economics"
 * Strips leading domain segment if it matches the domain field.
 *
 * @param {string} topicId
 * @param {string} domain
 * @returns {string}
 */
function topicLabel(topicId, domain) {
  const domainSlug = (domain || '').toLowerCase().replace(/\s+/g, '-');
  let label = topicId || '';

  // Strip leading domain prefix if present
  if (domainSlug && label.toLowerCase().startsWith(domainSlug + '-')) {
    label = label.slice(domainSlug.length + 1);
  }

  // Replace hyphens/underscores with spaces and trim
  return label.replace(/[-_]/g, ' ').trim();
}

/**
 * Build a domain-relevant scenario string for application mode.
 * Keeps it concrete by using the domain and topic together.
 *
 * @param {string} domain
 * @param {string} topic
 * @returns {string}
 */
function domainScenario(domain, topic) {
  const d = domain || 'your domain';
  const t = topic || 'this concept';
  return `a real-world ${d} situation involving ${t}`;
}

/**
 * Extract hints from the next_action field.
 * If next_action contains commas, split into steps.
 * Returns 2-3 hint strings.
 *
 * @param {string} nextAction
 * @param {string} topic
 * @returns {string[]}
 */
function hintsFromNextAction(nextAction, topic) {
  const raw = (nextAction || '').trim();
  if (!raw) {
    return [
      `Start by recalling what you know about ${topic}`,
      'Identify the key mechanism or definition',
      'Then consider a concrete example',
    ];
  }

  const parts = raw.split(',').map(s => s.trim()).filter(Boolean);
  if (parts.length >= 2) {
    return parts.slice(0, 3).map((p, i) => {
      const prefix = i === 0 ? 'First' : i === 1 ? 'Then' : 'Finally';
      // If the part already reads as a sentence, return it; otherwise prefix it
      return p.length > 40 ? p : `${prefix}: ${p.toLowerCase()}`;
    });
  }

  // Single step — expand into 2-3 related hints
  return [
    `Begin with: ${raw}`,
    `Consider what prior knowledge supports this`,
    `Identify where you feel least certain`,
  ];
}

/**
 * Extract the core concept from known_gaps.
 * Returns the first meaningful phrase (before any comma).
 *
 * @param {string} knownGaps
 * @returns {string}
 */
function primaryGap(knownGaps) {
  const raw = (knownGaps || '').trim();
  if (!raw || raw === 'none') return 'the core distinctions in this topic';
  const first = raw.split(',')[0].trim();
  return first || 'the core distinctions in this topic';
}

/**
 * Generate a knowledge check prompt from a mastery note's inline fields.
 *
 * @param {object} inlineFields  - parsed inline fields from mastery note
 * @param {'recall'|'application'|'synthesis'} mode
 * @returns {{ prompt: string, hints: string[], expected_thinking: string, mode: string, topic_id: string }}
 */
export function generatePrompt(inlineFields, mode) {
  const topicId = (inlineFields.topic_id || '').trim();
  const domain = (inlineFields.domain || '').trim();
  const knownGaps = (inlineFields.known_gaps || '').trim();
  const nextAction = (inlineFields.next_action || '').trim();

  const topic = topicLabel(topicId, domain);
  const gap = primaryGap(knownGaps);

  switch (mode) {
    case 'recall':
      return buildRecallPrompt(topic, domain, gap, nextAction, topicId);
    case 'application':
      return buildApplicationPrompt(topic, domain, gap, topicId);
    case 'synthesis':
      return buildSynthesisPrompt(topic, domain, gap, topicId);
    default:
      throw new Error(
        `Unknown mode "${mode}". Valid modes: recall, application, synthesis.`
      );
  }
}

/**
 * Build a recall-mode prompt.
 */
function buildRecallPrompt(topic, domain, gap, nextAction, topicId) {
  const gapClause = gap !== 'the core distinctions in this topic'
    ? ` Address these gaps if you can: ${gap}.`
    : '';

  const prompt =
    `In your own words, define: ${topic}.${gapClause}`;

  const hints = hintsFromNextAction(nextAction, topic);

  const expected_thinking =
    `State the definition clearly, then explain why it matters in context of ${domain || 'this domain'}.`;

  return { prompt, hints, expected_thinking, mode: 'recall', topic_id: topicId };
}

/**
 * Build an application-mode prompt.
 */
function buildApplicationPrompt(topic, domain, gap, topicId) {
  const scenario = domainScenario(domain, topic);

  const prompt =
    `You are analyzing ${scenario}. How does ${topic} apply? ` +
    `What would change if ${gap} was different?`;

  const hints = [
    'Think about cause and effect',
    'Consider the direction of the relationship',
    'What would break first?',
  ];

  const expected_thinking =
    `Apply the concept to the scenario, trace the mechanism, identify what varies.`;

  return { prompt, hints, expected_thinking, mode: 'application', topic_id: topicId };
}

/**
 * Build a synthesis-mode prompt.
 */
function buildSynthesisPrompt(topic, domain, gap, topicId) {
  const domainLabel = domain || 'the broader field';

  const prompt =
    `How does ${topic} connect to broader patterns in ${domainLabel}? ` +
    `If ${gap} changed, what second-order effects would ripple through?`;

  const hints = [
    'Start with the direct effect',
    'Then consider who else is affected',
    'Then consider timing',
  ];

  const expected_thinking =
    `Chain effects across at least 2 levels, name specific mechanisms.`;

  return { prompt, hints, expected_thinking, mode: 'synthesis', topic_id: topicId };
}

/**
 * Return available modes and their descriptions.
 *
 * @returns {{ id: string, label: string, description: string }[]}
 */
export function getModes() {
  return [
    { id: 'recall', label: 'Recall', description: 'Can you state what it is?' },
    { id: 'application', label: 'Application', description: 'Can you use it in a scenario?' },
    { id: 'synthesis', label: 'Synthesis', description: 'Can you connect it to other ideas?' },
