// server.mjs — Learning web app HTTP server (port 4747)

import http from 'http';
import { readFile, writeFile, readdir, mkdir } from 'fs/promises';
import { join, extname, basename } from 'path';
import { fileURLToPath } from 'url';

import { getLearningPaths, parseInlineFields, serializeMastery, appendCheckHistory, readNote, readFolder } from './lib/vault.mjs';
import { buildIndex, search, getNote } from './lib/search.mjs';

const __dirname = fileURLToPath(new URL('.', import.meta.url));

// --- Search index cache ---
let _searchIndex = null;
let _indexBuiltAt = 0;
const INDEX_TTL_MS = 5 * 60 * 1000; // 5 minutes

async function getSearchIndex() {
  const paths = getLearningPaths();
  const now = Date.now();
  if (!_searchIndex || now - _indexBuiltAt > INDEX_TTL_MS) {
    _searchIndex = await buildIndex(paths.root);
    _indexBuiltAt = now;
  }
  return _searchIndex;
}

// --- Server bootstrap ---
export function startServer(port) {
  const server = http.createServer(handleRequest);
  server.listen(port, () => {
    console.log(`Learning app running at http://localhost:${port}`);
  });
  return server;
}

// --- Request router ---
async function handleRequest(req, res) {
  const url = new URL(req.url, `http://localhost`);
  const pathname = url.pathname;
  const method = req.method;

  try {
    // Static files
    if (method === 'GET' && pathname === '/') {
      return await serveFile(res, join(__dirname, 'index.html'), 'text/html');
    }

    if (method === 'GET' && pathname.startsWith('/public/')) {
      const file = pathname.slice('/public/'.length);
      return await serveFile(res, join(__dirname, 'public', file), mimeType(file));
    }

    // API routes
    if (pathname.startsWith('/api/learn/')) {
      return await routeApi(req, res, method, pathname, url);
    }

    sendError(res, 'Not found', 404);
  } catch (err) {
    sendError(res, err.message, 500);
  }
}

async function routeApi(req, res, method, pathname, url) {
  const paths = getLearningPaths();
  const segment = pathname.slice('/api/learn/'.length);
  const parts = segment.split('/');

  // GET /api/learn/overview
  if (method === 'GET' && segment === 'overview') {
    return await handleOverview(res, paths);
  }

  // GET /api/learn/session
  if (method === 'GET' && segment === 'session') {
    const date = url.searchParams.get('date') || todayStr();
    return await handleSession(res, paths, date);
  }

  // POST /api/learn/session/update
  if (method === 'POST' && segment === 'session/update') {
    const body = await readBody(req);
    return await handleSessionUpdate(res, paths, body);
  }

  // GET /api/learn/mastery
  if (method === 'GET' && segment === 'mastery') {
    return await handleMasteryList(res, paths);
  }

  // GET /api/learn/mastery/:topicId
  if (method === 'GET' && parts[0] === 'mastery' && parts.length === 2) {
    return await handleMasteryDetail(res, paths, decodeURIComponent(parts[1]));
  }

  // GET /api/learn/domains
  if (method === 'GET' && segment === 'domains') {
    return await handleDomains(res, paths);
  }

  // GET /api/learn/nodes
  if (method === 'GET' && segment === 'nodes') {
    const domain = url.searchParams.get('domain') || null;
    const progressState = url.searchParams.get('progress_state') || null;
    return await handleNodes(res, paths, domain, progressState);
  }

  // GET /api/learn/assignments
  if (method === 'GET' && segment === 'assignments') {
    const state = url.searchParams.get('state') || null;
    return await handleAssignments(res, paths, state);
  }

  // GET /api/learn/assignment/:id
  if (method === 'GET' && parts[0] === 'assignment' && parts.length === 2) {
    return await handleAssignmentDetail(res, paths, decodeURIComponent(parts[1]));
  }

  // GET /api/learn/library/search
  if (method === 'GET' && segment === 'library/search') {
    const q = url.searchParams.get('q') || '';
    const filters = {
      domain: url.searchParams.get('domain') || null,
      tag: url.searchParams.get('tag') || null,
      note_type: url.searchParams.get('type') || null,
      folder: url.searchParams.get('folder') || null,
    };
    return await handleLibrarySearch(res, paths, q, filters);
  }

  // GET /api/learn/library/note
  if (method === 'GET' && segment === 'library/note') {
    const notePath = url.searchParams.get('path') || '';
    return await handleLibraryNote(res, paths, notePath);
  }

  // GET /api/learn/library/resources
  if (method === 'GET' && segment === 'library/resources') {
    const domain = url.searchParams.get('domain') || null;
    return await handleResources(res, paths, domain);
  }

  // GET /api/learn/notebook
  if (method === 'GET' && segment === 'notebook') {
    return await handleNotebookList(res, paths);
  }

  // GET /api/learn/notebook/:slug
  if (method === 'GET' && parts[0] === 'notebook' && parts.length === 2) {
    return await handleNotebookGet(res, paths, decodeURIComponent(parts[1]));
  }

  // POST /api/learn/notebook/:slug
  if (method === 'POST' && parts[0] === 'notebook' && parts.length === 2) {
    const body = await readBody(req);
    return await handleNotebookPost(res, paths, decodeURIComponent(parts[1]), body);
  }

  // POST /api/learn/checkpoint
  if (method === 'POST' && segment === 'checkpoint') {
    const body = await readBody(req);
    return await handleCheckpoint(res, paths, body);
  }

  // GET /api/learn/check/generate
  if (method === 'GET' && segment === 'check/generate') {
    const topicId = url.searchParams.get('topic_id') || '';
    const mode = url.searchParams.get('mode') || 'recall';
    return await handleCheckGenerate(res, paths, topicId, mode);
  }

  // POST /api/learn/check/submit
  if (method === 'POST' && segment === 'check/submit') {
    const body = await readBody(req);
    return await handleCheckSubmit(res, paths, body);
  }

  // GET /api/learn/graph
  if (method === 'GET' && segment === 'graph') {
    return await handleGraph(res, paths);
  }

  sendError(res, 'API route not found', 404);
}

// --- Route handlers ---

async function handleOverview(res, paths) {
  const today = todayStr();
  const sessionNote = await findSessionNote(paths, today);
  const masteryNotes = await loadAllMastery(paths);

  const summary = { active: 0, complete: 0, locked: 0, total: 0 };
  let recommended = null;

  for (const note of masteryNotes) {
    summary.total++;
    const state = note.inlineFields.progress_state || '';
    if (state === 'active') summary.active++;
    else if (state === 'complete') summary.complete++;
    else if (state === 'locked') summary.locked++;

    if (!recommended && state === 'active') {
      recommended = {
        topic_id: note.inlineFields.topic_id,
        domain: note.inlineFields.domain,
        next_action: note.inlineFields.next_action,
        level: note.inlineFields.level,
      };
    }
  }

  const streak = await calculateStreak(paths);

  sendJson(res, {
    today_session: sessionNote
      ? {
          date: today,
          nodes_created: sessionNote.inlineFields.nodes_created,
          clarity_score: sessionNote.inlineFields.clarity_score,
          active_project: sessionNote.inlineFields.active_project || sessionNote.data.active_project,
        }
      : null,
    mastery_summary: summary,
    recommended_next: recommended,
    streak,
  });
}

async function handleSession(res, paths, date) {
  const note = await findSessionNote(paths, date);
  if (!note) return sendError(res, `No session note found for ${date}`, 404);
  sendJson(res, { date, data: note.data, inlineFields: note.inlineFields, content: note.content });
}

async function handleSessionUpdate(res, paths, body) {
  const { date, field, value } = body;
  if (!date || !field) return sendError(res, 'date and field required', 400);

  const note = await findSessionNote(paths, date || todayStr());
  if (!note) return sendError(res, 'Session note not found', 404);

  const rawText = await readFile(note.filePath, 'utf8');
  const updated = serializeMastery(rawText, { [field]: value });
  await writeFile(note.filePath, updated, 'utf8');
  sendJson(res, { success: true });
}

async function handleMasteryList(res, paths) {
  const notes = await loadAllMastery(paths);
  const result = notes.map(n => ({
    path: n.path,
    topic_id: n.inlineFields.topic_id,
    domain: n.inlineFields.domain,
    level: n.inlineFields.level,
    confidence: n.inlineFields.confidence,
    stability: n.inlineFields.stability,
    progress_state: n.inlineFields.progress_state,
    next_action: n.inlineFields.next_action,
    last_reviewed: n.inlineFields.last_reviewed,
  }));
  sendJson(res, result);
}

async function handleMasteryDetail(res, paths, topicId) {
  const note = await findMasteryByTopicId(paths, topicId);
  if (!note) return sendError(res, `Mastery note not found for topic_id: ${topicId}`, 404);
  sendJson(res, { path: note.path, data: note.data, inlineFields: note.inlineFields, content: note.content });
}

async function handleDomains(res, paths) {
  let entries;
  try {
    entries = await readdir(paths.domains, { withFileTypes: true });
  } catch {
    return sendJson(res, []);
  }

  const domains = [];
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const overviewPath = join(paths.domains, entry.name, 'Overview.md');
    try {
      const raw = await readFile(overviewPath, 'utf8');
      const { data } = parseRawNote(raw);
      domains.push({
        name: data.domain_name || entry.name,
        slug: entry.name,
        path: overviewPath,
        data,
      });
    } catch {
      // Skip missing overview files
    }
  }
  sendJson(res, domains);
}

async function handleNodes(res, paths, domain, progressState) {
  let files;
  try {
    files = await readdir(paths.nodes, { withFileTypes: true });
  } catch {
    return sendJson(res, []);
  }

  const nodes = [];
  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const filePath = join(paths.nodes, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data, content } = parseRawNote(raw);
      const inlineFields = parseInlineFields(content);

      if (domain && (data.primary_domain || '').toLowerCase() !== domain.toLowerCase()) continue;
      if (progressState && (data.mastery_level || inlineFields.progress_state || '') !== progressState) continue;

      nodes.push({ path: filePath, filename: f.name, data });
    } catch {
      // skip
    }
  }
  sendJson(res, nodes);
}

async function handleAssignments(res, paths, state) {
  let files;
  try {
    files = await readdir(paths.projects, { withFileTypes: true });
  } catch {
    return sendJson(res, []);
  }

  const projects = [];
  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const filePath = join(paths.projects, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data } = parseRawNote(raw);
      if (state && data.project_status !== state) continue;
      projects.push({ path: filePath, filename: f.name, data });
    } catch {
      // skip
    }
  }
  sendJson(res, projects);
}

async function handleAssignmentDetail(res, paths, id) {
  let files;
  try {
    files = await readdir(paths.projects, { withFileTypes: true });
  } catch {
    return sendError(res, 'Projects directory not found', 404);
  }

  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const slug = f.name.replace(/\.md$/, '').toLowerCase().replace(/\s+/g, '-');
    if (slug !== id.toLowerCase()) continue;

    const filePath = join(paths.projects, f.name);
    const raw = await readFile(filePath, 'utf8');
    const { data, content } = parseRawNote(raw);
    return sendJson(res, { path: filePath, data, content });
  }

  sendError(res, `Assignment not found: ${id}`, 404);
}

async function handleLibrarySearch(res, paths, q, filters) {
  const index = await getSearchIndex();
  // Remove null filters
  const cleanFilters = Object.fromEntries(Object.entries(filters).filter(([, v]) => v !== null));
  const results = search(index, q, cleanFilters);
  sendJson(res, results);
}

async function handleLibraryNote(res, paths, notePath) {
  if (!notePath) return sendError(res, 'path query param required', 400);
  try {
    const note = await getNote(paths.root, notePath);
    sendJson(res, note);
  } catch (err) {
    sendError(res, err.message, 404);
  }
}

async function handleResources(res, paths, domain) {
  let files;
  try {
    files = await readdir(paths.resources, { withFileTypes: true });
  } catch {
    return sendJson(res, []);
  }

  const resources = [];
  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const filePath = join(paths.resources, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data } = parseRawNote(raw);
      if (domain && (data.domain || '').toLowerCase() !== domain.toLowerCase()) continue;
      resources.push({ path: filePath, filename: f.name, data });
    } catch {
      // skip
    }
  }
  sendJson(res, resources);
}

async function handleNotebookList(res, paths) {
  await ensureDir(paths.notebooks);
  let files;
  try {
    files = await readdir(paths.notebooks, { withFileTypes: true });
  } catch {
    return sendJson(res, []);
  }

  const notebooks = [];
  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const filePath = join(paths.notebooks, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data, content } = parseRawNote(raw);
      const snippet = content.trim().slice(0, 200);
      notebooks.push({ filename: f.name, path: filePath, data, snippet });
    } catch {
      // skip
    }
  }
  sendJson(res, notebooks);
}

async function handleNotebookGet(res, paths, slug) {
  await ensureDir(paths.notebooks);
  const filePath = join(paths.notebooks, `${slug}.md`);
  try {
    const raw = await readFile(filePath, 'utf8');
    const { data, content } = parseRawNote(raw);
    sendJson(res, { path: filePath, data, content });
  } catch {
    sendError(res, `Notebook not found: ${slug}`, 404);
  }
}

async function handleNotebookPost(res, paths, slug, body) {
  await ensureDir(paths.notebooks);
  const { content } = body;
  if (typeof content !== 'string') return sendError(res, 'content string required', 400);

  const filePath = join(paths.notebooks, `${slug}.md`);
  await writeFile(filePath, content, 'utf8');
  sendJson(res, { success: true, path: filePath });
}

async function handleCheckpoint(res, paths, body) {
  const { topic_id, mastery_delta = 0, confidence_delta = 0, notes = '', check_type = 'manual' } = body;
  if (!topic_id) return sendError(res, 'topic_id required', 400);

  const note = await findMasteryByTopicId(paths, topic_id);
  if (!note) return sendError(res, `Mastery note not found: ${topic_id}`, 404);

  const rawText = await readFile(note.filePath, 'utf8');
  const current = note.inlineFields;

  const newLevel = Math.max(0, Math.min(5, (Number(current.level) || 0) + mastery_delta));
  const newConfidence = Math.max(0, Math.min(10, (Number(current.confidence) || 0) + confidence_delta));

  // Evaluate unlock
  let unlockResult = { new_level: newLevel, new_stability: current.stability, new_confidence: newConfidence, unlocked_topic_ids: [] };
  try {
    const { evaluateUnlock } = await import('./lib/unlock.mjs');
    unlockResult = evaluateUnlock(
      { ...current, level: newLevel, confidence: newConfidence },
      { topic_id, mastery_delta, confidence_delta, notes, check_type }
    );
  } catch {
    // unlock.mjs not yet implemented — use defaults
  }

  const updates = {
    level: unlockResult.new_level ?? newLevel,
    confidence: unlockResult.new_confidence ?? newConfidence,
    stability: unlockResult.new_stability ?? current.stability,
    last_reviewed: todayStr(),
  };

  const entry = {
    date: todayStr(),
    mode: check_type,
    result: mastery_delta >= 0 ? 'pass' : 'fail',
    response_text: notes,
  };

  let updated = serializeMastery(rawText, updates);
  updated = appendCheckHistory(updated, entry);
  await writeFile(note.filePath, updated, 'utf8');

  sendJson(res, {
    success: true,
    new_level: updates.level,
    new_stability: updates.stability,
    new_confidence: updates.confidence,
    unlocked_nodes: unlockResult.unlocked_topic_ids || [],
    next_action: current.next_action,
  });
}

async function handleCheckGenerate(res, paths, topicId, mode) {
  if (!topicId) return sendError(res, 'topic_id required', 400);

  const note = await findMasteryByTopicId(paths, topicId);
  if (!note) return sendError(res, `Mastery note not found: ${topicId}`, 404);

  try {
    const { generatePrompt } = await import('./lib/checks.mjs');
    const result = generatePrompt(note.inlineFields, mode);
    sendJson(res, { ...result, mode, topic_id: topicId });
  } catch {
    sendError(res, 'checks.mjs not yet implemented', 501);
  }
}

async function handleCheckSubmit(res, paths, body) {
  const { topic_id, mode, result, response_text } = body;
  if (!topic_id) return sendError(res, 'topic_id required', 400);

  const note = await findMasteryByTopicId(paths, topic_id);
  if (!note) return sendError(res, `Mastery note not found: ${topic_id}`, 404);

  const rawText = await readFile(note.filePath, 'utf8');
  const entry = {
    date: todayStr(),
    mode: mode || 'recall',
    result: result || 'unknown',
    response_text: response_text || '',
  };

  let updated = appendCheckHistory(rawText, entry);

  let unlocked_topic_ids = [];
  try {
    const { evaluateUnlock } = await import('./lib/unlock.mjs');
    const unlockResult = evaluateUnlock(note.inlineFields, body);
    unlocked_topic_ids = unlockResult.unlocked_topic_ids || [];
    const stateUpdates = {
      level: unlockResult.new_level,
      confidence: unlockResult.new_confidence,
      stability: unlockResult.new_stability,
      last_reviewed: todayStr(),
    };
    updated = serializeMastery(updated, stateUpdates);
  } catch {
    // unlock.mjs not yet available
  }

  await writeFile(note.filePath, updated, 'utf8');
  sendJson(res, { success: true, unlocked_topic_ids });
}

async function handleGraph(res, paths) {
  const notes = await loadAllMastery(paths);
  const nodes = notes.map(n => ({
    id: n.inlineFields.topic_id || basename(n.path, '.md'),
    label: n.inlineFields.topic_id || basename(n.path, '.md'),
    domain: n.inlineFields.domain || '',
    level: n.inlineFields.level || 0,
    progress_state: n.inlineFields.progress_state || '',
  }));
  sendJson(res, { nodes, edges: [] });
}

// --- Helpers ---

async function loadAllMastery(paths) {
  let files;
  try {
    files = await readdir(paths.mastery, { withFileTypes: true });
  } catch {
    return [];
  }

  const notes = [];
  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const filePath = join(paths.mastery, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data, content } = parseRawNote(raw);
      const inlineFields = parseInlineFields(content);
      notes.push({ path: filePath, filePath, data, content, inlineFields });
    } catch {
      // skip
    }
  }
  return notes;
}

async function findMasteryByTopicId(paths, topicId) {
  const notes = await loadAllMastery(paths);
  return notes.find(n => n.inlineFields.topic_id === topicId) || null;
}

async function findSessionNote(paths, date) {
  let files;
  try {
    files = await readdir(paths.sessions, { withFileTypes: true });
  } catch {
    return null;
  }

  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    if (!f.name.startsWith(date)) continue;

    const filePath = join(paths.sessions, f.name);
    try {
      const raw = await readFile(filePath, 'utf8');
      const { data, content } = parseRawNote(raw);
      const inlineFields = parseInlineFields(content);
      return { filePath, data, content, inlineFields };
    } catch {
      return null;
    }
  }
  return null;
}

async function calculateStreak(paths) {
  let files;
  try {
    files = await readdir(paths.sessions, { withFileTypes: true });
  } catch {
    return 0;
  }

  const sessionDates = new Set(
    files
      .filter(f => f.isFile() && extname(f.name) === '.md')
      .map(f => f.name.slice(0, 10))
      .filter(d => /^\d{4}-\d{2}-\d{2}$/.test(d))
  );

  let streak = 0;
  let current = new Date();
  current.setHours(0, 0, 0, 0);

  while (true) {
    const dateStr = current.toISOString().slice(0, 10);
    if (!sessionDates.has(dateStr)) break;
    streak++;
    current.setDate(current.getDate() - 1);
  }

  return streak;
}

function parseRawNote(raw) {
  const fmMatch = raw.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
  if (!fmMatch) return { data: {}, content: raw };

  const yamlBlock = fmMatch[1];
  const content = fmMatch[2];
  const data = parseSimpleYaml(yamlBlock);
  return { data, content };
}

function parseSimpleYaml(yaml) {
  const result = {};
  const lines = yaml.split('\n');
  let currentKey = null;
  let currentArray = null;

  for (const line of lines) {
    const arrayItem = line.match(/^  - (.+)$/);
    if (arrayItem && currentArray !== null) {
      currentArray.push(arrayItem[1].trim());
      continue;
    }

    const kv = line.match(/^([a-zA-Z_][a-zA-Z0-9_]*):\s*(.*)$/);
    if (kv) {
      currentKey = kv[1];
      const val = kv[2].trim();
      if (val === '' || val === '[]') {
        currentArray = [];
        result[currentKey] = currentArray;
      } else {
        currentArray = null;
        result[currentKey] = val.replace(/^["']|["']$/g, '');
      }
    }
  }

  return result;
}

async function ensureDir(dirPath) {
  try {
    await mkdir(dirPath, { recursive: true });
  } catch {
    // already exists
  }
}

async function serveFile(res, filePath, contentType) {
  try {
    const content = await readFile(filePath);
    res.writeHead(200, { 'Content-Type': contentType });
    res.end(content);
  } catch {
    sendError(res, 'File not found', 404);
  }
}

function mimeType(filename) {
  const ext = extname(filename).toLowerCase();
  const map = {
    '.html': 'text/html',
    '.js': 'application/javascript',
    '.mjs': 'application/javascript',
    '.css': 'text/css',
    '.json': 'application/json',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.svg': 'image/svg+xml',
  };
  return map[ext] || 'application/octet-stream';
}

function sendJson(res, data, status = 200) {
  const body = JSON.stringify(data);
  res.writeHead(status, {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(body),
  });
  res.end(body);
}

function sendError(res, msg, status = 400) {
  sendJson(res, { error: msg }, status);
}

async function readBody(req) {
  return new Promise((resolve, reject) => {
    let data = '';
    req.on('data', chunk => { data += chunk; });
    req.on('end', () => {
      try {
        resolve(data ? JSON.parse(data) : {});
      } catch {
        reject(new Error('Invalid JSON body'));
      }
    });
    req.on('error', reject);
  });
}

function todayStr() {
  return new Date().toISOString().slice(0, 10);
}

