/* ============================================================
   CSS Custom Properties
   ============================================================ */
:root {
  --color-bg: #0f1117;
  --color-card: #1a1d27;
  --color-accent: #4f9cf9;
  --color-text: #e2e8f0;
  --color-muted: #64748b;
  --color-border: #2d3148;

  --color-success: #22c55e;
  --color-warning: #f59e0b;
  --color-danger: #ef4444;

  /* Status colors for mastery states */
  --color-active: #4f9cf9;
  --color-complete: #22c55e;
  --color-locked: #64748b;
  --color-mastered: #a78bfa;

  /* Spacing */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 16px;
  --space-lg: 24px;
  --space-xl: 32px;

  /* Border radius */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
}

/* ============================================================
   Reset
   ============================================================ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ============================================================
   Layout
   ============================================================ */
.layout {
  display: flex;
  flex-direction: row;
  height: 100vh;
}

.sidebar {
  width: 200px;
  min-width: 200px;
  flex-shrink: 0;
}

.main-content {
  flex: 1;
  overflow-y: auto;
  padding: var(--space-lg);
}

/* ============================================================
   Cards
   ============================================================ */
.card {
  background: var(--color-card);
  border-radius: var(--radius-md);
  padding: var(--space-md);
  border: 1px solid var(--color-border);
}

.card + .card {
  margin-top: var(--space-md);
}

/* ============================================================
   Typography
   ============================================================ */
.heading-1 {
  font-size: 22px;
  font-weight: 700;
  color: var(--color-text);
  line-height: 1.3;
}

.heading-2 {
  font-size: 16px;
  font-weight: 600;
  color: var(--color-text);
  line-height: 1.4;
}

.label {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.muted {
  color: var(--color-muted);
  font-size: 13px;
}

/* ============================================================
   Badges
   ============================================================ */
.badge {
  display: inline-block;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.04em;
  background: var(--color-border);
  color: var(--color-text);
}

.badge-active {
  background: rgba(79, 156, 249, 0.15);
  color: var(--color-active);
  border: 1px solid rgba(79, 156, 249, 0.3);
}

.badge-complete {
  background: rgba(34, 197, 94, 0.15);
  color: var(--color-complete);
  border: 1px solid rgba(34, 197, 94, 0.3);
}

.badge-locked {
  background: rgba(100, 116, 139, 0.15);
  color: var(--color-locked);
  border: 1px solid rgba(100, 116, 139, 0.3);
}

.badge-mastered {
  background: rgba(167, 139, 250, 0.15);
  color: var(--color-mastered);
  border: 1px solid rgba(167, 139, 250, 0.3);
}

/* ============================================================
   Buttons
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-xs);
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  border: none;
  transition: opacity 0.15s, background 0.15s;
  text-decoration: none;
}

.btn:hover {
  opacity: 0.85;
}

.btn:active {
  opacity: 0.7;
}

.btn-primary {
  background: var(--color-accent);
  color: #fff;
}

.btn-secondary {
  background: var(--color-border);
  color: var(--color-text);
}

.btn-sm {
  padding: 5px 12px;
  font-size: 12px;
}

/* ============================================================
   Forms
   ============================================================ */
.form-group {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  margin-bottom: var(--space-md);
}

.form-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-muted);
}

.form-input {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text);
  font-size: 13px;
  padding: 8px 10px;
  outline: none;
  transition: border-color 0.15s;
}

.form-input:focus {
  border-color: var(--color-accent);
}

.form-textarea {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  color: var(--color-text);
  font-size: 13px;
  padding: 8px 10px;
  outline: none;
  resize: vertical;
  min-height: 80px;
  font-family: inherit;
  transition: border-color 0.15s;
}

.form-textarea:focus {
  border-color: var(--color-accent);
}

/* ============================================================
   Tables
   ============================================================ */
.data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

.data-table th {
  text-align: left;
  padding: 8px 12px;
  font-size: 11px;
  font-weight: 600;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 1px solid var(--color-border);
}

.data-table td {
  padding: 10px 12px;
  border-bottom: 1px solid rgba(45, 49, 72, 0.5);
  color: var(--color-text);
  vertical-align: middle;
}

.data-table tbody tr:hover {
  background: rgba(79, 156, 249, 0.04);
  cursor: pointer;
}

.data-table tbody tr:last-child td {
  border-bottom: none;
}

/* ============================================================
   Progress Bar
   ============================================================ */
.progress-bar {
  width: 100%;
  background: var(--color-border);
  border-radius: 99px;
  height: 6px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  border-radius: 99px;
  background: var(--color-accent);
  transition: width 0.3s ease;
}

.progress-fill.fill-success {
  background: var(--color-success);
}

.progress-fill.fill-warning {
  background: var(--color-warning);
}

/* ============================================================
   Spinner
   ============================================================ */
.spinner {
  width: 32px;
  height: 32px;
  border: 3px solid var(--color-border);
  border-top-color: var(--color-accent);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ============================================================
   Utility
   ============================================================ */
.flex { display: flex; }
.flex-col { flex-direction: column; }
.items-center { align-items: center; }
.justify-between { justify-content: space-between; }
.gap-sm { gap: var(--space-sm); }
.gap-md { gap: var(--space-md); }
.mt-sm { margin-top: var(--space-sm); }
.mt-md { margin-top: var(--space-md); }
.mt-lg { margin-top: var(--space-lg); }

.error-card {
  background: rgba(239, 68, 68, 0.08);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  color: var(--color-danger);
  font-size: 14px;
}

.stat-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
  gap: var(--space-md);
}

.stat-card {
  background: var(--color-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--space-md);
  text-align: center;
}

.stat-card .stat-value {
  font-size: 28px;
  font-weight: 700;
  line-height: 1;
  margin-bottom: 4px;
}

.stat-card .stat-label {
  font-size: 11px;
  font-weight: 600;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

