// views/library.js — Full-text search library view

let query = '';
let selectedDomain = '';
let selectedType = '';
let selectedNote = null;
let activeTab = 'search';
let debounceTimer = null;

export async function render(container, ctx) {
  // Reset state on each mount
  query = '';
  selectedDomain = '';
  selectedType = '';
  selectedNote = null;
  activeTab = 'search';

  container.innerHTML = buildShell();
  attachTabListeners(container, ctx);
  attachSearchListeners(container, ctx);
  renderEmptyState(container);
}

// ---------------------------------------------------------------------------
// Shell HTML
// ---------------------------------------------------------------------------

function buildShell() {
  return `
    <div id="lib-root" style="display:flex;flex-direction:column;height:100%;gap:0.75rem;">

      <!-- Tab row -->
      <div style="display:flex;gap:0.5rem;border-bottom:1px solid #333;padding-bottom:0.5rem;">
        <button id="tab-search" class="btn btn-primary btn-sm">Search</button>
        <button id="tab-resources" class="btn btn-sm">Resources</button>
      </div>

      <!-- Search panel -->
      <div id="panel-search" style="display:flex;flex-direction:column;flex:1;gap:0.75rem;min-height:0;">

        <!-- Filter row -->
        <div style="display:flex;gap:0.5rem;align-items:center;flex-wrap:wrap;">
          <input
            id="lib-search-input"
            class="form-input"
            type="text"
            placeholder="Search learning materials..."
            value=""
            style="flex:1;min-width:180px;"
          />
          <select id="lib-filter-domain" class="form-input" style="width:140px;">
            <option value="">All Domains</option>
          </select>
          <select id="lib-filter-type" class="form-input" style="width:140px;">
            <option value="">All Types</option>
          </select>
        </div>

        <!-- Two-column results + detail -->
        <div style="display:flex;flex:1;gap:1rem;min-height:0;overflow:hidden;">

          <!-- Results list -->
          <div id="lib-results"
               style="width:340px;flex-shrink:0;overflow-y:auto;display:flex;flex-direction:column;gap:0.5rem;">
            <p class="muted" id="lib-empty-state">Type to search</p>
          </div>

          <!-- Note detail panel -->
          <div id="lib-detail"
               style="flex:1;overflow-y:auto;display:none;padding:0.5rem 0;">
          </div>

        </div>
      </div>

      <!-- Resources panel -->
      <div id="panel-resources" style="display:none;flex:1;overflow-y:auto;">
        <p class="muted">Loading resources…</p>
      </div>

    </div>
  `;
}

// ---------------------------------------------------------------------------
// Tab logic
// ---------------------------------------------------------------------------

function attachTabListeners(container, ctx) {
  const btnSearch = container.querySelector('#tab-search');
  const btnResources = container.querySelector('#tab-resources');

  btnSearch.addEventListener('click', () => {
    activeTab = 'search';
    btnSearch.classList.add('btn-primary');
    btnResources.classList.remove('btn-primary');
    container.querySelector('#panel-search').style.display = 'flex';
    container.querySelector('#panel-resources').style.display = 'none';
  });

  btnResources.addEventListener('click', async () => {
    activeTab = 'resources';
    btnResources.classList.add('btn-primary');
    btnSearch.classList.remove('btn-primary');
    container.querySelector('#panel-search').style.display = 'none';
    const panel = container.querySelector('#panel-resources');
    panel.style.display = 'block';
    panel.innerHTML = '<p class="muted">Loading resources…</p>';
    await loadResources(panel, ctx);
  });
}

// ---------------------------------------------------------------------------
// Search logic
// ---------------------------------------------------------------------------

function attachSearchListeners(container, ctx) {
  const input = container.querySelector('#lib-search-input');
  const domainSel = container.querySelector('#lib-filter-domain');
  const typeSel = container.querySelector('#lib-filter-type');

  input.addEventListener('input', () => {
    query = input.value.trim();
    scheduleSearch(container, ctx);
  });

  domainSel.addEventListener('change', () => {
    selectedDomain = domainSel.value;
    scheduleSearch(container, ctx);
  });

  typeSel.addEventListener('change', () => {
    selectedType = typeSel.value;
    scheduleSearch(container, ctx);
  });
}

function scheduleSearch(container, ctx) {
  clearTimeout(debounceTimer);
  if (!query) {
    renderEmptyState(container);
    return;
  }
  debounceTimer = setTimeout(() => runSearch(container, ctx), 300);
}

async function runSearch(container, ctx) {
  const resultsEl = container.querySelector('#lib-results');
  resultsEl.innerHTML = '<div class="spinner"></div>';

  const params = new URLSearchParams({ q: query });
  if (selectedDomain) params.set('domain', selectedDomain);
  if (selectedType) params.set('type', selectedType);

  let data;
  try {
    const res = await ctx.api.get(`/api/learn/library/search?${params}`);
    data = await res.json();
  } catch (err) {
    resultsEl.innerHTML = `<p class="muted">Error: ${escapeHtml(String(err.message))}</p>`;
    return;
  }

  const results = Array.isArray(data) ? data : (data.results || []);
  renderResults(container, ctx, results);
  populateFilterOptions(container, results);
}

function renderEmptyState(container) {
  const resultsEl = container.querySelector('#lib-results');
  if (resultsEl) {
    resultsEl.innerHTML = '<p class="muted" id="lib-empty-state">Type to search</p>';
  }
  const detail = container.querySelector('#lib-detail');
  if (detail) {
    detail.style.display = 'none';
    detail.innerHTML = '';
  }
}

function renderResults(container, ctx, results) {
  const resultsEl = container.querySelector('#lib-results');

  if (!results.length) {
    resultsEl.innerHTML = '<p class="muted">No results found.</p>';
    return;
  }

  resultsEl.innerHTML = results.map((r, i) => `
    <div class="card" data-idx="${i}" style="cursor:pointer;padding:0.6rem 0.8rem;">
      <div style="font-weight:600;margin-bottom:0.25rem;">${escapeHtml(r.title || r.path || 'Untitled')}</div>
      ${r.snippet ? `<div class="muted" style="font-size:0.85em;margin-bottom:0.4rem;">${escapeHtml(r.snippet)}</div>` : ''}
      <div style="display:flex;gap:0.4rem;flex-wrap:wrap;align-items:center;">
        ${r.domain ? `<span class="badge">${escapeHtml(r.domain)}</span>` : ''}
        ${r.note_type || r.type ? `<span class="badge">${escapeHtml(r.note_type || r.type)}</span>` : ''}
        ${r.score != null ? `<span class="muted" style="font-size:0.78em;margin-left:auto;">score: ${Number(r.score).toFixed(2)}</span>` : ''}
      </div>
    </div>
  `).join('');

  // Attach click handlers
  resultsEl.querySelectorAll('.card[data-idx]').forEach(card => {
    card.addEventListener('click', () => {
      const idx = parseInt(card.dataset.idx, 10);
      loadNoteDetail(container, ctx, results[idx]);
    });
  });
}

function populateFilterOptions(container, results) {
  const domains = [...new Set(results.map(r => r.domain).filter(Boolean))];
  const types = [...new Set(results.map(r => r.note_type || r.type).filter(Boolean))];

  const domainSel = container.querySelector('#lib-filter-domain');
  const currentDomain = domainSel.value;
  domainSel.innerHTML = '<option value="">All Domains</option>' +
    domains.map(d => `<option value="${escapeHtml(d)}" ${d === currentDomain ? 'selected' : ''}>${escapeHtml(d)}</option>`).join('');

  const typeSel = container.querySelector('#lib-filter-type');
  const currentType = typeSel.value;
  typeSel.innerHTML = '<option value="">All Types</option>' +
    types.map(t => `<option value="${escapeHtml(t)}" ${t === currentType ? 'selected' : ''}>${escapeHtml(t)}</option>`).join('');
}

// ---------------------------------------------------------------------------
// Note detail
// ---------------------------------------------------------------------------

async function loadNoteDetail(container, ctx, result) {
  selectedNote = result;
  const detail = container.querySelector('#lib-detail');
  detail.style.display = 'block';
  detail.innerHTML = '<div class="spinner"></div>';

  let note;
  try {
    const res = await ctx.api.get(`/api/learn/library/note?path=${encodeURIComponent(result.path || result.title)}`);
    note = await res.json();
  } catch (err) {
    detail.innerHTML = `<p class="muted">Could not load note: ${escapeHtml(String(err.message))}</p>`;
    return;
  }

  detail.innerHTML = renderNoteDetail(note);
}

function renderNoteDetail(note) {
  const meta = note.metadata || note.frontmatter || {};
  const tags = Array.isArray(meta.tags) ? meta.tags : (meta.tags ? [meta.tags] : []);
  const inlineFields = note.inline_fields || note.fields || null;

  const inlineTable = inlineFields && Object.keys(inlineFields).length
    ? `<table class="data-table" style="margin-top:0.75rem;">
        <thead><tr><th>Field</th><th>Value</th></tr></thead>
        <tbody>
          ${Object.entries(inlineFields).map(([k, v]) =>
            `<tr><td>${escapeHtml(k)}</td><td>${escapeHtml(String(v))}</td></tr>`
          ).join('')}
        </tbody>
       </table>`
    : '';

  return `
    <h2 class="heading-2" style="margin-bottom:0.5rem;">${escapeHtml(note.title || 'Untitled')}</h2>
    <div style="display:flex;gap:0.4rem;flex-wrap:wrap;margin-bottom:0.75rem;align-items:center;">
      ${meta.domain ? `<span class="badge">${escapeHtml(meta.domain)}</span>` : ''}
      ${meta.note_type || meta.type ? `<span class="badge">${escapeHtml(meta.note_type || meta.type)}</span>` : ''}
      ${tags.map(t => `<span class="badge">${escapeHtml(t)}</span>`).join('')}
    </div>
    ${inlineTable}
    <pre style="white-space:pre-wrap;word-break:break-word;font-size:0.85em;margin-top:0.75rem;padding:0.75rem;background:#1a1a1a;border-radius:4px;overflow-x:auto;">${escapeHtml(note.content || '')}</pre>
  `;
}

// ---------------------------------------------------------------------------
// Resources tab
// ---------------------------------------------------------------------------

async function loadResources(panel, ctx) {
  let data;
  try {
    const res = await ctx.api.get('/api/learn/library/resources');
    data = await res.json();
  } catch (err) {
    panel.innerHTML = `<p class="muted">Error loading resources: ${escapeHtml(String(err.message))}</p>`;
    return;
  }

  // Expect data as array of { domain, resources: [...] } or flat array
  const groups = Array.isArray(data) ? data : (data.groups || []);

  if (!groups.length) {
    panel.innerHTML = '<p class="muted">No resources found.</p>';
    return;
  }

  panel.innerHTML = groups.map(group => `
    <div style="margin-bottom:1.5rem;">
      <h3 class="heading-2" style="margin-bottom:0.5rem;">${escapeHtml(group.domain || group.name || 'General')}</h3>
      <div style="display:flex;flex-wrap:wrap;gap:0.5rem;">
        ${(group.resources || group.items || []).map(r => `
          <div class="card" style="min-width:200px;max-width:280px;padding:0.6rem 0.8rem;">
            <div style="font-weight:600;margin-bottom:0.2rem;">${escapeHtml(r.title || r.name || 'Resource')}</div>
            ${r.url ? `<a href="${escapeHtml(r.url)}" target="_blank" rel="noopener" style="font-size:0.82em;word-break:break-all;">${escapeHtml(r.url)}</a>` : ''}
            ${r.description ? `<p class="muted" style="font-size:0.82em;margin-top:0.2rem;">${escapeHtml(r.description)}</p>` : ''}
          </div>
        `).join('')}
      </div>
    </div>
  `).join('');
}

// ---------------------------------------------------------------------------
// Utility
// ---------------------------------------------------------------------------

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

