  'knowledge-check': './views/knowledge-check.js',
  assignment: './views/assignment.js',
};

const DEFAULT_HASH = 'observatory';

// ============================================================
// Context Object
// ============================================================
const ctx = {
  navigate(hash) {
    window.location.hash = hash;
  },
  api,
};

