const mainContent = document.getElementById('main-content');
const viewContainer = document.getElementById('view-container');
const loadingOverlay = document.getElementById('loading-overlay');
const navLinks = document.querySelectorAll('.nav-link');
const statActive = document.getElementById('stat-active');
const statTotal = document.getElementById('stat-total');

// ============================================================
// Spinner helpers
// ============================================================
function showSpinner() {
  loadingOverlay.classList.add('visible');
}

function hideSpinner() {
  loadingOverlay.classList.remove('visible');
}

// ============================================================
// Active nav update
// ============================================================
function updateActiveNav(hash) {
  navLinks.forEach((link) => {
    const linkHash = link.getAttribute('data-hash');
    if (linkHash === hash) {
      link.classList.add('active');
    } else {
      link.classList.remove('active');
    }
  });
}

// ============================================================
// Sidebar progress update
// ============================================================
async function updateSidebarProgress() {
  try {
    const overview = await api.get('/api/learn/overview');
    const summary = overview.mastery_summary || {};
    if (statActive) statActive.textContent = summary.active ?? '—';
    if (statTotal) statTotal.textContent = summary.total ?? '—';
  } catch {
    // Non-fatal — sidebar stats stay showing dashes
  }
}

// ============================================================
// Router
// ============================================================
async function handleRoute() {
  const rawHash = window.location.hash.replace('#', '').split('?')[0].trim();
  const hash = rawHash || DEFAULT_HASH;

  // Ensure we have a hash in the URL
  if (!rawHash) {
    window.location.hash = DEFAULT_HASH;
    return; // hashchange will re-fire
  }

  const modulePath = routes[hash];

  updateActiveNav(hash);
  showSpinner();
  viewContainer.innerHTML = '';

  try {
    if (!modulePath) {
      viewContainer.innerHTML = `
        <div class="error-card">
          <strong>404</strong> — No view found for <code>#${hash}</code>.
        </div>`;
      return;
    }

    const module = await import(modulePath);

    if (typeof module.render !== 'function') {
      throw new Error(`View module "${modulePath}" does not export a render() function.`);
    }

    await module.render(viewContainer, ctx);
  } catch (err) {
    console.error('[router] View render error:', err);
    viewContainer.innerHTML = `
      <div class="error-card">
        <strong>Failed to load view</strong><br/>
        <span style="opacity:0.7;font-size:12px;">${err.message}</span>
      </div>`;
  } finally {
    hideSpinner();
    updateSidebarProgress();
  }
}

// ============================================================
// Boot
// ============================================================
window.addEventListener('hashchange', handleRoute);
window.addEventListener('load', handleRoute);

