// views/checkpoint.js — Checkpoint Chamber

function getHashParams() {
  const [, query] = window.location.hash.split('?');
  return Object.fromEntries(new URLSearchParams(query ?? ''));
}

function levelBadge(level) {
  return `<span class="badge">${level ?? '—'}</span>`;
}

function formatDate(iso) {
  if (!iso) return '—';
  return new Date(iso).toLocaleDateString();
}

// ── Step 1: Topic Selection ───────────────────────────────────────────────────

async function renderTopicSelection(container, ctx, onSelect) {
  container.innerHTML = `
    <h1 class="heading-1">Checkpoint Chamber</h1>
    <p class="muted">Select a mastery area to checkpoint.</p>
    <div class="form-group">
      <label class="form-label" for="cp-topic-search">Search topics</label>
      <input id="cp-topic-search" class="form-input" type="text" placeholder="Filter by name or domain…" />
    </div>
    <div id="cp-topic-list"><span class="spinner"></span></div>
  `;

  let areas = [];
  try {
    const res = await ctx.api.get('/api/learn/mastery');
    const data = await res.json();
    areas = (data.areas ?? data).filter(a => a.progress_state === 'active');
  } catch (err) {
    container.querySelector('#cp-topic-list').innerHTML =
      `<p class="muted">Failed to load mastery areas: ${err.message}</p>`;
    return;
  }

  const listEl = container.querySelector('#cp-topic-list');
  const searchEl = container.querySelector('#cp-topic-search');

  function renderList(filter) {
    const filtered = filter
      ? areas.filter(a =>
          (a.topic_id ?? '').toLowerCase().includes(filter) ||
          (a.domain ?? '').toLowerCase().includes(filter)
        )
      : areas;

    if (!filtered.length) {
      listEl.innerHTML = `<p class="muted">No active topics match.</p>`;
      return;
    }

    listEl.innerHTML = filtered.map(a => `
      <div class="card" style="cursor:pointer;margin-bottom:0.5rem"
           data-topic-id="${a.topic_id}">
        <strong>${a.topic_id}</strong>
        <span class="badge" style="margin-left:0.5rem">${a.domain ?? ''}</span>
        <span style="margin-left:1rem">${levelBadge(a.current_level)}</span>
        <span class="muted" style="margin-left:0.5rem">confidence: ${a.current_confidence ?? '—'}</span>
      </div>
    `).join('');

    listEl.querySelectorAll('[data-topic-id]').forEach(el => {
      el.addEventListener('click', () => onSelect(el.dataset.topicId));
    });
  }

  renderList('');
  searchEl.addEventListener('input', () => renderList(searchEl.value.toLowerCase().trim()));
}

// ── Step 2: Checkpoint Form ───────────────────────────────────────────────────

async function renderCheckpointForm(container, ctx, topicId, onResult) {
  container.innerHTML = `<span class="spinner"></span>`;

  let area;
  try {
    const res = await ctx.api.get('/api/learn/mastery');
    const data = await res.json();
    const areas = data.areas ?? data;
    area = areas.find(a => a.topic_id === topicId);
    if (!area) throw new Error(`Topic not found: ${topicId}`);
  } catch (err) {
    container.innerHTML = `<p class="muted">Error loading topic: ${err.message}</p>`;
    return;
  }

  const history = (area.check_history ?? []).slice(-5).reverse();

  container.innerHTML = `
    <h1 class="heading-1">Checkpoint Chamber</h1>

    <div class="card" style="margin-bottom:1rem">
      <h2 class="heading-2" style="margin:0 0 0.25rem">
        ${area.topic_id}
        <span class="badge" style="margin-left:0.5rem">${area.domain ?? ''}</span>
      </h2>
      <p class="muted" style="margin:0">
        Level: ${levelBadge(area.current_level)}
        &nbsp;|&nbsp; Confidence: <strong>${area.current_confidence ?? '—'}</strong>
        &nbsp;|&nbsp; Stability: <strong>${area.current_stability ?? '—'}</strong>
      </p>
    </div>

    <form id="cp-form" class="card">
      <div class="form-group">
        <span class="form-label">Check Type</span>
        <label style="margin-right:1rem">
          <input type="radio" name="check_type" value="surface" checked /> Surface
        </label>
        <label>
          <input type="radio" name="check_type" value="advanced" /> Advanced
        </label>
      </div>

      <div class="form-group">
        <span class="form-label">Result</span>
        <label style="margin-right:1rem">
          <input type="radio" name="result" value="pass" checked /> Pass
        </label>
        <label>
          <input type="radio" name="result" value="fail" /> Fail
        </label>
      </div>

      <div class="form-group">
        <label class="form-label" for="cp-confidence-delta">
          Confidence Delta: <span id="cp-delta-display">0</span>
        </label>
        <p class="muted" style="margin:0 0 0.25rem">How did this feel? Adjust confidence.</p>
        <input id="cp-confidence-delta" type="range" min="-20" max="30" value="0"
               style="width:100%" />
        <div style="display:flex;justify-content:space-between">
          <span class="muted">−20</span><span class="muted">+30</span>
        </div>
      </div>

      <div class="form-group">
        <label class="form-label" for="cp-notes">Notes</label>
        <p class="muted" style="margin:0 0 0.25rem">
          What did you work on? What evidence did you encounter?
        </p>
        <textarea id="cp-notes" class="form-input form-textarea" rows="4"
                  placeholder="Write your notes here…"></textarea>
      </div>

      <div id="cp-submit-error" style="color:red;display:none;margin-bottom:0.5rem"></div>
      <button id="cp-submit" type="submit" class="btn btn-primary">Submit Checkpoint</button>
    </form>

    ${area.next_action ? `
      <div class="card" style="margin-top:1rem">
        <strong class="form-label">Next Action</strong>
        <p style="margin:0.25rem 0 0">${area.next_action}</p>
      </div>
    ` : ''}

    ${history.length ? `
      <div class="card" style="margin-top:1rem">
        <strong class="form-label">Recent Check History</strong>
        <table class="data-table" style="margin-top:0.5rem;width:100%">
          <thead>
            <tr><th>Date</th><th>Mode</th><th>Result</th></tr>
          </thead>
          <tbody>
            ${history.map(h => `
              <tr>
                <td>${formatDate(h.date)}</td>
                <td>${h.mode ?? h.check_type ?? '—'}</td>
                <td>${h.result ?? '—'}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
    ` : ''}
  `;

  // Slider live display
  const slider = container.querySelector('#cp-confidence-delta');
  const deltaDisplay = container.querySelector('#cp-delta-display');
  slider.addEventListener('input', () => {
    const v = parseInt(slider.value, 10);
    deltaDisplay.textContent = v > 0 ? `+${v}` : `${v}`;
  });

  // Form submit
  const form = container.querySelector('#cp-form');
  const submitBtn = container.querySelector('#cp-submit');
  const errorEl = container.querySelector('#cp-submit-error');

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    submitBtn.disabled = true;
    submitBtn.textContent = 'Submitting…';
    errorEl.style.display = 'none';

    const checkType = form.querySelector('[name=check_type]:checked').value;
    const result = form.querySelector('[name=result]:checked').value;
    const confidenceDelta = parseInt(slider.value, 10);
    const notes = container.querySelector('#cp-notes').value.trim();

    try {
      const res = await ctx.api.post('/api/learn/checkpoint', {
        topic_id: topicId,
        mastery_delta: 0,
        confidence_delta: confidenceDelta,
        notes,
        check_type: checkType,
        result,
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error ?? `Server error ${res.status}`);
      onResult(data, topicId);
    } catch (err) {
      errorEl.textContent = err.message;
      errorEl.style.display = 'block';
      submitBtn.disabled = false;
      submitBtn.textContent = 'Submit Checkpoint';
    }
  });
}

// ── Step 3: Result Display ────────────────────────────────────────────────────

function renderCheckpointResult(container, ctx, result, topicId) {
  const unlocked = result.unlocked_nodes ?? [];

  container.innerHTML = `
    <h1 class="heading-1">Checkpoint Complete</h1>

    <div class="card" style="margin-bottom:1rem">
      <h2 class="heading-2" style="margin:0 0 0.5rem">${topicId}</h2>
      <p style="margin:0">
        New Level: ${levelBadge(result.new_level ?? result.level)}
        &nbsp;|&nbsp; Confidence: <strong>${result.new_confidence ?? result.confidence ?? '—'}</strong>
        &nbsp;|&nbsp; Stability: <strong>${result.new_stability ?? result.stability ?? '—'}</strong>
      </p>
    </div>

    ${unlocked.length ? `
      <div class="card" style="background:#d4edda;border-color:#28a745;margin-bottom:1rem">
        <strong>You unlocked:</strong>
        <ul style="margin:0.5rem 0 0;padding-left:1.5rem">
          ${unlocked.map(n => `<li>${n}</li>`).join('')}
        </ul>
      </div>
    ` : ''}

    <div style="display:flex;gap:0.75rem;flex-wrap:wrap">
      <button id="cp-go-observatory" class="btn btn-secondary">Return to Observatory</button>
      <button id="cp-go-knowledge-check" class="btn btn-primary">Run Knowledge Check</button>
    </div>
  `;

  container.querySelector('#cp-go-observatory').addEventListener('click', () => {
    ctx.navigate('#observatory');
  });
  container.querySelector('#cp-go-knowledge-check').addEventListener('click', () => {
    ctx.navigate(`#knowledge-check?topic_id=${encodeURIComponent(topicId)}`);
  });
}

// ── Entry Point ───────────────────────────────────────────────────────────────

export async function render(container, ctx) {
  const params = getHashParams();
  let topicId = params.topic_id ?? null;

  if (topicId) {
    await renderCheckpointForm(container, ctx, topicId, (result, tid) => {
      renderCheckpointResult(container, ctx, result, tid);
    });
  } else {
    await renderTopicSelection(container, ctx, async (selected) => {
      topicId = selected;
      await renderCheckpointForm(container, ctx, topicId, (result, tid) => {
        renderCheckpointResult(container, ctx, result, tid);
      });
    });
  }
}

