// views/notebook.js — Personal notebook editor view

let currentSlug = null;
let isDirty = false;
let notebookCtx = null;

export async function render(container, ctx) {
  notebookCtx = ctx;
  currentSlug = null;
  isDirty = false;

  container.innerHTML = buildShell();
  attachNewNoteListener(container, ctx);
  await loadNoteList(container, ctx);
}

// ---------------------------------------------------------------------------
// Shell HTML
// ---------------------------------------------------------------------------

function buildShell() {
  return `
    <div id="nb-root" style="display:flex;height:100%;gap:0;min-height:0;">

      <!-- Sidebar -->
      <div id="nb-sidebar"
           style="width:220px;flex-shrink:0;display:flex;flex-direction:column;border-right:1px solid #333;padding:0.5rem 0.5rem 0.5rem 0;">

        <button id="nb-new-btn" class="btn btn-primary btn-sm" style="margin-bottom:0.75rem;">
          + New Note
        </button>

        <div id="nb-note-list"
             style="flex:1;overflow-y:auto;display:flex;flex-direction:column;gap:0.25rem;">
          <p class="muted" style="font-size:0.85em;">Loading…</p>
        </div>
      </div>

      <!-- Editor area -->
      <div id="nb-editor-area"
           style="flex:1;display:flex;flex-direction:column;padding:0.75rem;min-width:0;">

        <div id="nb-editor-heading"
             style="font-size:1.1rem;font-weight:600;margin-bottom:0.5rem;color:#aaa;">
          Select a note or create a new one
        </div>

        <div id="nb-editor-controls" style="display:none;margin-bottom:0.5rem;">
          <button id="nb-save-btn" class="btn btn-primary btn-sm">Save</button>
          <span id="nb-dirty-indicator" style="font-size:0.8em;color:#f0a500;margin-left:0.5rem;display:none;">Unsaved changes</span>
        </div>

        <textarea
          id="nb-textarea"
          class="form-textarea"
          placeholder="Start writing…"
          style="
            flex:1;
            width:100%;
            resize:none;
            font-family:monospace;
            font-size:0.9em;
            background:#111;
            color:#e0e0e0;
            border:1px solid #333;
            border-radius:4px;
            padding:0.75rem;
            line-height:1.6;
            display:none;
            box-sizing:border-box;
          "
        ></textarea>

      </div>

    </div>

    <!-- Toast container -->
    <div id="nb-toast"
         style="
           position:fixed;
           bottom:1.5rem;
           right:1.5rem;
           background:#2a7a2a;
           color:#fff;
           padding:0.6rem 1.2rem;
           border-radius:6px;
           font-size:0.9em;
           display:none;
           z-index:9999;
           transition:opacity 0.4s ease;
           opacity:1;
         ">
      Saved to vault ✓
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Note list
// ---------------------------------------------------------------------------

async function loadNoteList(container, ctx) {
  const listEl = container.querySelector('#nb-note-list');
  listEl.innerHTML = '<p class="muted" style="font-size:0.85em;">Loading…</p>';

  let notes;
  try {
    const res = await ctx.api.get('/api/learn/notebook');
    notes = await res.json();
  } catch (err) {
    listEl.innerHTML = `<p class="muted" style="font-size:0.82em;">Error: ${escapeHtml(String(err.message))}</p>`;
    return;
  }

  const items = Array.isArray(notes) ? notes : (notes.notes || []);

  if (!items.length) {
    listEl.innerHTML = '<p class="muted" style="font-size:0.85em;">No notes yet.</p>';
    return;
  }

  listEl.innerHTML = items.map(note => {
    const slug = note.slug || note.id || slugify(note.title || note.name || 'untitled');
    const label = note.title || note.name || slug;
    return `
      <div class="card nb-note-item"
           data-slug="${escapeHtml(slug)}"
           style="cursor:pointer;padding:0.4rem 0.6rem;font-size:0.88em;word-break:break-word;">
        ${escapeHtml(label)}
      </div>
    `;
  }).join('');

  listEl.querySelectorAll('.nb-note-item').forEach(item => {
    item.addEventListener('click', () => {
      const slug = item.dataset.slug;
      openNote(container, ctx, slug, item.textContent.trim());
    });
  });
}

// ---------------------------------------------------------------------------
// Open note
// ---------------------------------------------------------------------------

async function openNote(container, ctx, slug, title) {
  if (isDirty) {
    const ok = window.confirm('You have unsaved changes. Discard and switch notes?');
    if (!ok) return;
  }

  currentSlug = slug;
  isDirty = false;

  const textarea = container.querySelector('#nb-textarea');
  const heading = container.querySelector('#nb-editor-heading');
  const controls = container.querySelector('#nb-editor-controls');
  const dirtyIndicator = container.querySelector('#nb-dirty-indicator');

  heading.textContent = title || slug;
  heading.style.color = '#e0e0e0';
  controls.style.display = 'block';
  dirtyIndicator.style.display = 'none';
  textarea.style.display = 'block';
  textarea.value = '';

  try {
    const res = await ctx.api.get(`/api/learn/notebook/${encodeURIComponent(slug)}`);
    const data = await res.json();
    textarea.value = data.content || '';
  } catch (err) {
    textarea.value = `# Error loading note\n\n${err.message}`;
  }

  // Track dirty state
  textarea.oninput = () => {
    isDirty = true;
    dirtyIndicator.style.display = 'inline';
  };

  // Save button
  const saveBtn = container.querySelector('#nb-save-btn');
  saveBtn.onclick = () => saveNote(container, ctx);
}

// ---------------------------------------------------------------------------
// New note
// ---------------------------------------------------------------------------

function attachNewNoteListener(container, ctx) {
  const btn = container.querySelector('#nb-new-btn');
  btn.addEventListener('click', () => createNewNote(container, ctx));
}

function createNewNote(container, ctx) {
  if (isDirty) {
    const ok = window.confirm('You have unsaved changes. Discard and create a new note?');
    if (!ok) return;
  }

  const title = window.prompt('Note title:');
  if (!title || !title.trim()) return;

  const trimmedTitle = title.trim();
  const slug = slugify(trimmedTitle);

  currentSlug = slug;
  isDirty = true;

  const textarea = container.querySelector('#nb-textarea');
  const heading = container.querySelector('#nb-editor-heading');
  const controls = container.querySelector('#nb-editor-controls');
  const dirtyIndicator = container.querySelector('#nb-dirty-indicator');

  heading.textContent = trimmedTitle;
  heading.style.color = '#e0e0e0';
  controls.style.display = 'block';
  dirtyIndicator.style.display = 'inline';
  textarea.style.display = 'block';
  textarea.value = `# ${trimmedTitle}\n\n`;
  textarea.focus();
  // Place cursor at end
  textarea.selectionStart = textarea.selectionEnd = textarea.value.length;

  textarea.oninput = () => {
    isDirty = true;
    dirtyIndicator.style.display = 'inline';
  };

  const saveBtn = container.querySelector('#nb-save-btn');
  saveBtn.onclick = () => saveNote(container, ctx);
}

// ---------------------------------------------------------------------------
// Save note
// ---------------------------------------------------------------------------

async function saveNote(container, ctx) {
  if (!currentSlug) return;

  const textarea = container.querySelector('#nb-textarea');
  const dirtyIndicator = container.querySelector('#nb-dirty-indicator');
  const saveBtn = container.querySelector('#nb-save-btn');

  saveBtn.disabled = true;
  saveBtn.textContent = 'Saving…';

  try {
    await ctx.api.post(`/api/learn/notebook/${encodeURIComponent(currentSlug)}`, {
      content: textarea.value,
    });
    isDirty = false;
    dirtyIndicator.style.display = 'none';
    showToast(container);
    await loadNoteList(container, ctx);
  } catch (err) {
    window.alert(`Save failed: ${err.message}`);
  } finally {
    saveBtn.disabled = false;
    saveBtn.textContent = 'Save';
  }
}

// ---------------------------------------------------------------------------
// Toast
// ---------------------------------------------------------------------------

function showToast(container) {
  const toast = document.querySelector('#nb-toast');
  if (!toast) return;

  toast.style.display = 'block';
  toast.style.opacity = '1';

  setTimeout(() => {
    toast.style.opacity = '0';
    setTimeout(() => {
      toast.style.display = 'none';
      toast.style.opacity = '1';
    }, 400);
  }, 2000);
}

// ---------------------------------------------------------------------------
// Utility
// ---------------------------------------------------------------------------

function slugify(title) {
  return title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-');
}

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

