content.newText:
// ============================================================
// Observatory View — Home dashboard
// ============================================================

function levelBadgeClass(level) {
  if (level >= 5) return 'badge-mastered';
  if (level >= 3) return 'badge-complete';
  if (level >= 1) return 'badge-active';
  return 'badge-locked';
}

function confidenceBarHTML(value, max = 1) {
  const pct = Math.min(100, Math.round((value / max) * 100));
  return `
    <div class="progress-bar" style="width:80px">
      <div class="progress-fill" style="width:${pct}%"></div>
    </div>`;
}

function clarityBarHTML(value, max = 10) {
  const pct = Math.min(100, Math.round((value / max) * 100));
  const fillClass = pct >= 70 ? 'fill-success' : pct >= 40 ? '' : 'fill-warning';
  return `
    <div style="display:flex;align-items:center;gap:8px;">
      <div class="progress-bar" style="flex:1">
        <div class="progress-fill ${fillClass}" style="width:${pct}%"></div>
      </div>
      <span style="font-size:12px;color:var(--color-muted);white-space:nowrap">${value ?? '—'} / ${max}</span>
    </div>`;
}

function statCardHTML(label, value, colorVar) {
  return `
    <div class="stat-card">
      <div class="stat-value" style="color:var(${colorVar})">${value ?? '—'}</div>
      <div class="stat-label">${label}</div>
    </div>`;
}

function renderActiveMasteryTable(items, navigate) {
  if (!items || items.length === 0) {
    return `<p class="muted" style="padding:12px 0;">No active mastery areas right now.</p>`;
  }

  const rows = items.map((item) => {
    const topicId = item.topic_id || item.id || '';
    const level = item.level ?? 0;
    const confidence = item.confidence ?? 0;
    return `
      <tr data-topic-id="${topicId}" style="cursor:pointer">
        <td>${item.topic || item.title || topicId}</td>
        <td>${item.domain || '—'}</td>
        <td><span class="badge ${levelBadgeClass(level)}">${level}</span></td>
        <td>${confidenceBarHTML(confidence)}</td>
        <td><span class="muted">${item.next_action || '—'}</span></td>
      </tr>`;
  }).join('');

  return `
    <table class="data-table">
      <thead>
        <tr>
          <th>Topic</th>
          <th>Domain</th>
          <th>Level</th>
          <th>Confidence</th>
          <th>Next Action</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>`;
}

export async function render(container, ctx) {
  // Show inline spinner while both fetches run
  container.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:center;padding:60px;">
      <div class="spinner"></div>
    </div>`;

  let overview, masteryItems;

  try {
    [overview, masteryItems] = await Promise.all([
      ctx.api.get('/api/learn/overview'),
      ctx.api.get('/api/learn/mastery'),
    ]);
  } catch (err) {
    container.innerHTML = `
      <div class="error-card">
        <strong>Could not load observatory data</strong><br/>
        <span style="opacity:0.7;font-size:12px;">${err.message}</span>
      </div>`;
    return;
  }

  const {
    today_session: session = {},
    mastery_summary: summary = {},
    recommended_next: rec = {},
    streak = 0,
  } = overview;

  const activeItems = (masteryItems || []).filter(
