// ============================================================
// Assignment Studio View
// ============================================================

function statusBadgeClass(status) {
  switch (status) {
    case 'active': return 'badge-active';
    case 'complete': return 'badge-complete';
    case 'locked': return 'badge-locked';
    case 'mastered': return 'badge-mastered';
    default: return '';
  }
}

function progressBarHTML(level, max = 5) {
  const pct = Math.min(100, Math.round((level / max) * 100));
  return `
    <div style="display:flex;align-items:center;gap:8px;">
      <div class="progress-bar" style="flex:1">
        <div class="progress-fill" style="width:${pct}%"></div>
      </div>
      <span style="font-size:11px;color:var(--color-muted);white-space:nowrap">${level}/${max}</span>
    </div>`;
}

function renderProjectCard(project) {
  const domains = Array.isArray(project.domains)
    ? project.domains.join(', ')
    : (project.domain || '—');
  const level = project.level ?? project.progress_level ?? 0;
  const status = project.status || project.progress_state || 'active';
  const id = project.id || project.topic_id || '';

  return `
    <div class="card project-card" data-project-id="${id}" style="cursor:pointer;transition:border-color 0.15s;">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:10px;">
        <div class="heading-2">${project.name || project.title || id}</div>
        <span class="badge ${statusBadgeClass(status)}">${status}</span>
      </div>
      <div class="muted" style="margin-bottom:10px;">${domains}</div>
      <div>
        <div class="label" style="margin-bottom:6px;">Progress</div>
        ${progressBarHTML(level)}
      </div>
    </div>`;
}

function renderDetailPanel(assignment) {
  const coreNodes = Array.isArray(assignment.core_nodes) ? assignment.core_nodes : [];
  const originSessions = Array.isArray(assignment.origin_sessions) ? assignment.origin_sessions : [];

  const coreNodesHTML = coreNodes.length
    ? coreNodes.map((n) => `<li style="margin-bottom:4px;color:var(--color-text);">${n}</li>`).join('')
    : '<li class="muted">None listed</li>';

  const originsHTML = originSessions.length
    ? originSessions.map((s) => `<li style="margin-bottom:4px;color:var(--color-text);">${s}</li>`).join('')
    : '<li class="muted">None listed</li>';

  return `
    <div class="card" style="margin-top:0;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;">
        <div class="heading-2">${assignment.name || assignment.title || assignment.id}</div>
        <button class="btn btn-secondary btn-sm" id="btn-close-detail">&#8592; Back</button>
      </div>

      <!-- Content -->
      <div class="label" style="margin-bottom:8px;">Content</div>
      <pre style="
        background:var(--color-bg);
        border:1px solid var(--color-border);
        border-radius:var(--radius-sm);
        padding:12px;
        font-size:12px;
        color:var(--color-text);
        white-space:pre-wrap;
        word-break:break-word;
        overflow-x:auto;
        max-height:320px;
        overflow-y:auto;
        margin-bottom:16px;
        font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;
      ">${escapeHTML(assignment.content || '(no content)')}</pre>

      <!-- Core Nodes -->
      <div class="label" style="margin-bottom:8px;">Core Nodes</div>
      <ul style="list-style:disc;padding-left:18px;margin-bottom:16px;">
        ${coreNodesHTML}
      </ul>

      <!-- Origin Sessions -->
      <div class="label" style="margin-bottom:8px;">Origin Sessions</div>
      <ul style="list-style:disc;padding-left:18px;">
        ${originsHTML}
      </ul>
    </div>`;
}

function escapeHTML(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

async function loadDetail(container, projectId, ctx, projects) {
  // Show spinner inside detail panel
  container.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:center;padding:40px;">
      <div class="spinner"></div>
    </div>`;

  let assignment;
  try {
    assignment = await ctx.api.get(`/api/learn/assignment/${encodeURIComponent(projectId)}`);
  } catch (err) {
    container.innerHTML = `
      <div class="error-card">
        <strong>Failed to load assignment</strong><br/>
        <span style="opacity:0.7;font-size:12px;">${err.message}</span>
      </div>`;
    return;
  }

  container.innerHTML = renderDetailPanel(assignment);

  const backBtn = container.querySelector('#btn-close-detail');
  if (backBtn) {
    backBtn.addEventListener('click', () => {
      renderList(container, projects, ctx);
    });
  }
}

function renderList(container, projects, ctx) {
  if (!projects || projects.length === 0) {
    container.innerHTML = `
      <div class="heading-1" style="margin-bottom:8px;">Assignment Studio</div>
      <p class="muted">No active assignments found.</p>`;
    return;
  }

  container.innerHTML = `
    <div class="heading-1" style="margin-bottom:4px;">Assignment Studio</div>
    <p class="muted" style="margin-bottom:20px;">${projects.length} active project${projects.length !== 1 ? 's' : ''}</p>
    <div id="project-list" style="display:flex;flex-direction:column;gap:12px;">
      ${projects.map(renderProjectCard).join('')}
    </div>`;

  const list = container.querySelector('#project-list');
  if (list) {
    list.addEventListener('click', (e) => {
      const card = e.target.closest('.project-card[data-project-id]');
      if (!card) return;
      const id = card.getAttribute('data-project-id');
      if (id) {
        loadDetail(container, id, ctx, projects);
      }
    });

    // Hover highlight
    list.querySelectorAll('.project-card').forEach((card) => {
      card.addEventListener('mouseenter', () => {
        card.style.borderColor = 'var(--color-accent)';
      });
      card.addEventListener('mouseleave', () => {
        card.style.borderColor = 'var(--color-border)';
      });
    });
  }
}

export async function render(container, ctx) {
  container.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:center;padding:60px;">
      <div class="spinner"></div>
    </div>`;

  let projects;
  try {
    projects = await ctx.api.get('/api/learn/assignments?state=active');
  } catch (err) {
    container.innerHTML = `
      <div class="error-card">
        <strong>Could not load assignments</strong><br/>
        <span style="opacity:0.7;font-size:12px;">${err.message}</span>
      </div>`;
    return;
  }

  renderList(container, projects, ctx);
}

