// views/knowledge-check.js — Knowledge Check Arena

function getHashParams() {
  const [, query] = window.location.hash.split('?');
  return Object.fromEntries(new URLSearchParams(query ?? ''));
}

const MODE_META = {
  recall: {
    icon: '🔍',
    label: 'Recall',
    description: 'Can you state what it is?',
  },
  application: {
    icon: '⚙️',
    label: 'Application',
    description: 'Can you use it in a scenario?',
  },
  synthesis: {
    icon: '🔗',
    label: 'Synthesis',
    description: 'Can you connect it to other ideas?',
  },
};

// ── Topic Selector (no topic_id in URL) ──────────────────────────────────────

async function renderTopicSelector(container, ctx, onSelect) {
  container.innerHTML = `
    <h1 class="heading-1">Knowledge Check Arena</h1>
    <div class="form-group">
      <label class="form-label" for="kc-topic-select">Select a topic</label>
      <select id="kc-topic-select" class="form-input">
        <option value="">Loading…</option>
      </select>
    </div>
    <button id="kc-topic-confirm" class="btn btn-primary" disabled>Continue</button>
  `;

  const select = container.querySelector('#kc-topic-select');
  const confirmBtn = container.querySelector('#kc-topic-confirm');

  let areas = [];
  try {
    const res = await ctx.api.get('/api/learn/mastery');
    const data = await res.json();
    areas = (data.areas ?? data).filter(a => a.progress_state === 'active');
  } catch (err) {
    select.innerHTML = `<option value="">Failed to load: ${err.message}</option>`;
    return;
  }

  if (!areas.length) {
    select.innerHTML = `<option value="">No active topics found</option>`;
    return;
  }

  select.innerHTML = `<option value="">— choose a topic —</option>` +
    areas.map(a => `<option value="${a.topic_id}">${a.topic_id} (${a.domain ?? ''})</option>`).join('');

  select.addEventListener('change', () => {
    confirmBtn.disabled = !select.value;
  });

  confirmBtn.addEventListener('click', () => {
    if (select.value) onSelect(select.value);
  });
}

// ── Step 1: Mode Selection ────────────────────────────────────────────────────

function renderModeSelection(container, ctx, topicId, onMode) {
  const cards = Object.entries(MODE_META).map(([key, meta]) => `
    <div class="card" data-mode="${key}" style="cursor:pointer;flex:1;min-width:160px;text-align:center">
      <div style="font-size:2rem">${meta.icon}</div>
      <strong>${meta.label}</strong>
      <p class="muted" style="margin:0.25rem 0 0">${meta.description}</p>
    </div>
  `).join('');

  container.innerHTML = `
    <h1 class="heading-1">Knowledge Check Arena</h1>
    <p class="muted">Topic: <strong>${topicId}</strong></p>
    <div style="display:flex;gap:1rem;flex-wrap:wrap;margin-top:1rem">
      ${cards}
    </div>
  `;

  container.querySelectorAll('[data-mode]').forEach(el => {
    el.addEventListener('click', () => onMode(el.dataset.mode));
  });
}

// ── Step 2: Check Prompt ──────────────────────────────────────────────────────

async function renderCheckPrompt(container, ctx, topicId, mode, onResult) {
  container.innerHTML = `<span class="spinner"></span>`;

  let prompt;
  try {
    const res = await ctx.api.get(
      `/api/learn/check/generate?topic_id=${encodeURIComponent(topicId)}&mode=${encodeURIComponent(mode)}`
    );
    const data = await res.json();
    if (!res.ok) throw new Error(data.error ?? `Server error ${res.status}`);
    prompt = data;
  } catch (err) {
    container.innerHTML = `<p class="muted">Failed to load prompt: ${err.message}</p>`;
    return;
  }

  const meta = MODE_META[mode] ?? { icon: '', label: mode };
  const hints = prompt.hints ?? [];
  const expectedThinking = prompt.expected_thinking ?? prompt.expectedThinking ?? '';

  container.innerHTML = `
    <h1 class="heading-1">Knowledge Check Arena</h1>
    <p class="muted">Topic: <strong>${topicId}</strong> &nbsp;|&nbsp;
      <span class="badge">${meta.icon} ${meta.label}</span></p>

    <div class="card" style="margin:1rem 0">
      <p style="font-size:1.25rem;font-weight:600;margin:0">${prompt.prompt ?? prompt.text ?? ''}</p>
    </div>

    ${hints.length ? `
      <details style="margin-bottom:0.75rem">
        <summary style="cursor:pointer;font-weight:600">Show hints</summary>
        <ul style="margin:0.5rem 0 0;padding-left:1.5rem">
          ${hints.map(h => `<li>${h}</li>`).join('')}
        </ul>
      </details>
    ` : ''}

    ${expectedThinking ? `
      <details style="margin-bottom:1rem">
        <summary style="cursor:pointer;font-weight:600">What to aim for</summary>
        <p style="margin:0.5rem 0 0">${expectedThinking}</p>
      </details>
    ` : ''}

    <div class="form-group">
      <label class="form-label" for="kc-response">Your response</label>
      <textarea id="kc-response" class="form-input form-textarea" rows="6"
                placeholder="Write your response here…"></textarea>
    </div>

    <div style="margin-bottom:1rem">
      <p class="form-label" style="margin-bottom:0.5rem">
        How confident are you in this response?
      </p>
      <div style="display:flex;gap:0.5rem">
        <button class="btn btn-secondary btn-sm kc-confidence" data-delta="-10">Low (−10)</button>
        <button class="btn btn-secondary btn-sm kc-confidence" data-delta="0">Medium (0)</button>
        <button class="btn btn-secondary btn-sm kc-confidence" data-delta="10">High (+10)</button>
      </div>
      <input type="hidden" id="kc-confidence-delta" value="0" />
    </div>

    <div id="kc-submit-error" style="color:red;display:none;margin-bottom:0.5rem"></div>
    <button id="kc-submit" class="btn btn-primary">Submit Response</button>
  `;

  // Confidence selection
  let selectedDelta = 0;
  const confidenceInput = container.querySelector('#kc-confidence-delta');
  container.querySelectorAll('.kc-confidence').forEach(btn => {
    btn.addEventListener('click', () => {
      container.querySelectorAll('.kc-confidence').forEach(b => b.classList.remove('btn-primary'));
      btn.classList.add('btn-primary');
      selectedDelta = parseInt(btn.dataset.delta, 10);
      confidenceInput.value = selectedDelta;
    });
  });

  // Submit
  const submitBtn = container.querySelector('#kc-submit');
  const errorEl = container.querySelector('#kc-submit-error');

  submitBtn.addEventListener('click', async () => {
    const responseText = container.querySelector('#kc-response').value.trim();
    submitBtn.disabled = true;
    submitBtn.textContent = 'Submitting…';
    errorEl.style.display = 'none';

    try {
      const res = await ctx.api.post('/api/learn/check/submit', {
        topic_id: topicId,
        mode,
        result: 'pass',
        response_text: responseText,
        confidence_delta: selectedDelta,
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error ?? `Server error ${res.status}`);
      onResult(data, topicId, mode);
    } catch (err) {
      errorEl.textContent = err.message;
      errorEl.style.display = 'block';
      submitBtn.disabled = false;
      submitBtn.textContent = 'Submit Response';
    }
  });
}

// ── Step 3: Result ────────────────────────────────────────────────────────────

function renderCheckResult(container, ctx, result, topicId, mode) {
  const unlocked = result.unlocked_nodes ?? result.unlocked ?? [];

  container.innerHTML = `
    <h1 class="heading-1">Knowledge Check Arena</h1>

    <div class="card" style="background:#d4edda;border-color:#28a745;margin-bottom:1rem">
      <strong>Response saved ✓</strong>
    </div>

    ${unlocked.length ? `
      <div class="card" style="margin-bottom:1rem">
        <strong>Unlocked areas:</strong>
        <ul style="margin:0.5rem 0 0;padding-left:1.5rem">
          ${unlocked.map(n => `<li>${n}</li>`).join('')}
        </ul>
      </div>
    ` : ''}

    <div style="display:flex;gap:0.75rem;flex-wrap:wrap">
      <button id="kc-try-another" class="btn btn-secondary">Try Another Mode</button>
      <button id="kc-go-checkpoint" class="btn btn-secondary">Record Checkpoint</button>
      <button id="kc-go-home" class="btn btn-primary">Return Home</button>
    </div>
  `;

  container.querySelector('#kc-try-another').addEventListener('click', () => {
    renderModeSelection(container, ctx, topicId, (newMode) => {
      renderCheckPrompt(container, ctx, topicId, newMode, (res2, tid2, m2) => {
        renderCheckResult(container, ctx, res2, tid2, m2);
      });
    });
  });

  container.querySelector('#kc-go-checkpoint').addEventListener('click', () => {
    ctx.navigate(`#checkpoint?topic_id=${encodeURIComponent(topicId)}`);
  });

  container.querySelector('#kc-go-home').addEventListener('click', () => {
    ctx.navigate('#');
  });
}

// ── Entry Point ───────────────────────────────────────────────────────────────

export async function render(container, ctx) {
  const params = getHashParams();
  let topicId = params.topic_id ?? null;
  let mode = params.mode ?? null;

  const startWithTopic = async (tid) => {
    topicId = tid;
    if (mode) {
      await renderCheckPrompt(container, ctx, topicId, mode, (result, t, m) => {
        renderCheckResult(container, ctx, result, t, m);
      });
    } else {
      renderModeSelection(container, ctx, topicId, async (selectedMode) => {
        mode = selectedMode;
        await renderCheckPrompt(container, ctx, topicId, mode, (result, t, m) => {
          renderCheckResult(container, ctx, result, t, m);
        });
      });
    }
  };

  if (topicId) {
    await startWithTopic(topicId);
  } else {
    await renderTopicSelector(container, ctx, startWithTopic);
  }
}

