import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

// ─── Constants ───────────────────────────────────────────────────────────────

const STATE_COLOR = {
  locked:   0x4a5568,
  active:   0x4f9cf9,
  complete: 0xf59e0b,
  mastered: 0xffffff,
};

const STATE_LABEL_COLOR = {
  locked:   '#64748b',
  active:   '#4f9cf9',
  complete: '#f59e0b',
  mastered: '#ffffff',
};

const DOMAIN_SPACING = 9;
const LEVEL_SPACING  = 2.0;
const JITTER_XZ      = 2.5;
const JITTER_Y       = 0.5;
const NODE_RADIUS    = 0.35;

// ─── Seeded jitter ───────────────────────────────────────────────────────────

function seededVec3(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h) ^ str.charCodeAt(i);
  const s = (n) => { const v = Math.sin(n) * 43758.5453123; return v - Math.floor(v); };
  return {
    x: (s(h)      - 0.5) * 2,
    y: (s(h + 17) - 0.5) * 2,
    z: (s(h + 31) - 0.5) * 2,
  };
}

// ─── Canvas sprite label ─────────────────────────────────────────────────────

function makeTextSprite(text, color = '#94a3b8', scale = 1) {
  const canvas = document.createElement('canvas');
  canvas.width = 256; canvas.height = 64;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, 256, 64);
  ctx.font = 'bold 22px -apple-system, sans-serif';
  ctx.fillStyle = color;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(text, 128, 32);
  const tex = new THREE.CanvasTexture(canvas);
  const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthWrite: false });
  const sprite = new THREE.Sprite(mat);
  sprite.scale.set(4 * scale, 1 * scale, 1);
  return sprite;
}

// ─── Info panel ──────────────────────────────────────────────────────────────

function buildInfoPanel(container) {
  const panel = document.createElement('div');
  panel.style.cssText = [
    'position:absolute', 'top:16px', 'right:16px', 'width:260px',
    'background:rgba(26,29,39,0.95)', 'border:1px solid #2d3148',
    'border-radius:10px', 'padding:18px', 'display:none',
    'color:#e2e8f0', 'font-size:13px', 'z-index:10',
    'backdrop-filter:blur(8px)', 'box-shadow:0 8px 32px rgba(0,0,0,0.5)',
  ].join(';');
  container.appendChild(panel);
  return panel;
}

function renderInfoPanel(panel, node, ctx) {
