// ─── Main render ─────────────────────────────────────────────────────────────

export async function render(container, ctx) {
  // Take over the container — remove padding, fill full height
  container.style.cssText = [
    'position:relative', 'margin:-24px', 'overflow:hidden',
    'height:calc(100vh - 0px)', 'background:#090b11',
  ].join(';');

  // ── Fetch graph data ──────────────────────────────────────────────────────

  let graphData;
  try {
    graphData = await ctx.api.get('/api/learn/graph');
  } catch (err) {
    container.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;height:100%;color:#64748b;flex-direction:column;gap:12px">
        <div style="font-size:32px">✦</div>
        <div>Could not load graph data</div>
        <div style="font-size:12px;opacity:0.6">${err.message}</div>
      </div>`;
    return;
  }

  const nodes = graphData.nodes ?? [];

  if (nodes.length === 0) {
    container.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;height:100%;color:#64748b;flex-direction:column;gap:12px">
        <div style="font-size:48px">✦</div>
        <div>No mastery nodes found yet.</div>
        <div style="font-size:12px;opacity:0.6">Create your first session to populate the map.</div>
      </div>`;
    return;
  }

  // ── Domain layout ─────────────────────────────────────────────────────────

  const domains = [...new Set(nodes.map(n => n.domain ?? 'Unknown'))].sort();
  const domainCount = domains.length;
  const domainIdx = Object.fromEntries(domains.map((d, i) => [d, i]));

  // ── Scene setup ───────────────────────────────────────────────────────────

  const W = container.clientWidth;
  const H = container.clientHeight;

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x090b11);
  scene.fog = new THREE.FogExp2(0x090b11, 0.018);

  const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 500);
  camera.position.set(0, 6, domainCount * 2.5 + 12);
  camera.lookAt(0, 3, 0);

  const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = false;
  container.appendChild(renderer.domElement);

  // ── Controls ──────────────────────────────────────────────────────────────

  const controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping = true;
  controls.dampingFactor = 0.06;
  controls.minDistance = 3;
  controls.maxDistance = 120;
  controls.target.set(0, 3, 0);

  // ── Lighting ──────────────────────────────────────────────────────────────

  scene.add(new THREE.AmbientLight(0xffffff, 0.4));

  const keyLight = new THREE.DirectionalLight(0x88bbff, 1.2);
  keyLight.position.set(10, 20, 10);
  scene.add(keyLight);

  const fillLight = new THREE.PointLight(0x4f9cf9, 1.5, 60);
  fillLight.position.set(-8, 12, 0);
  scene.add(fillLight);

  // ── Background stars ──────────────────────────────────────────────────────

  const starGeo = new THREE.BufferGeometry();
  const starVerts = new Float32Array(1800);
  for (let i = 0; i < starVerts.length; i++) {
    starVerts[i] = (Math.random() - 0.5) * 200;
  }
  starGeo.setAttribute('position', new THREE.BufferAttribute(starVerts, 3));
  scene.add(new THREE.Points(starGeo, new THREE.PointsMaterial({ color: 0xffffff, size: 0.08, sizeAttenuation: true })));

  // ── Domain axis lines + labels ────────────────────────────────────────────

  const xOffset = (domainCount - 1) * DOMAIN_SPACING * 0.5;

  domains.forEach((domain, i) => {
    const x = i * DOMAIN_SPACING - xOffset;

    // Vertical axis ghost line
    const lineGeo = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(x, -0.5, 0),
      new THREE.Vector3(x, 5 * LEVEL_SPACING + 1, 0),
    ]);
    const line = new THREE.Line(lineGeo, new THREE.LineBasicMaterial({ color: 0x2d3148, transparent: true, opacity: 0.4 }));
    scene.add(line);

    // Domain label sprite below x-axis
    const label = makeTextSprite(domain.replace(/_/g, ' '), '#334155', 1.1);
    label.position.set(x, -1.5, 0);
    scene.add(label);
  });

  // ── Level labels (y-axis) ─────────────────────────────────────────────────

  for (let lv = 0; lv <= 5; lv++) {
    const label = makeTextSprite(`L${lv}`, '#334155', 0.7);
    label.position.set(-xOffset - 3, lv * LEVEL_SPACING, 0);
    scene.add(label);
  }

  // ── Node meshes ───────────────────────────────────────────────────────────

  const sharedGeo = new THREE.SphereGeometry(NODE_RADIUS, 20, 20);
  const glowGeo   = new THREE.SphereGeometry(NODE_RADIUS * 1.7, 14, 14);

  const nodeMeshes = [];

  nodes.forEach((node) => {
    const di = domainIdx[node.domain ?? 'Unknown'] ?? 0;
    const jitter = seededVec3(node.id ?? node.label ?? String(Math.random()));
    const x = di * DOMAIN_SPACING - xOffset + jitter.x * JITTER_XZ;
    const y = (node.level ?? 0) * LEVEL_SPACING + jitter.y * JITTER_Y;
    const z = jitter.z * JITTER_XZ;

    const color = STATE_COLOR[node.progress_state] ?? STATE_COLOR.locked;
    const isActive   = node.progress_state === 'active';
    const isComplete = node.progress_state === 'complete';
    const isMastered = node.progress_state === 'mastered';

    // Core sphere
    const mat = new THREE.MeshStandardMaterial({
      color,
      emissive: color,
      emissiveIntensity: isMastered ? 0.5 : isActive ? 0.25 : isComplete ? 0.15 : 0.02,
      roughness: 0.35,
      metalness: 0.2,
    });
    const mesh = new THREE.Mesh(sharedGeo, mat);
    mesh.position.set(x, y, z);
    mesh.userData = { node, isActive, isMastered, baseEmissive: mat.emissiveIntensity };
    scene.add(mesh);
    nodeMeshes.push(mesh);

    // Soft glow halo for active/complete/mastered nodes
    if (isActive || isComplete || isMastered) {
      const glowMat = new THREE.MeshBasicMaterial({
        color,
        transparent: true,
        opacity: isMastered ? 0.12 : 0.07,
        side: THREE.BackSide,
        depthWrite: false,
      });
      const glow = new THREE.Mesh(glowGeo, glowMat);
      glow.position.set(x, y, z);
      scene.add(glow);
    }

    // Short label under node
    const labelText = (node.label ?? node.id ?? '').replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
    const labelSprite = makeTextSprite(labelText, '#475569', 0.75);
    labelSprite.position.set(x, y - 0.65, z);
    scene.add(labelSprite);
  });

  // ── Info panel + legend ───────────────────────────────────────────────────

  const infoPanel = buildInfoPanel(container);
  buildLegend(container);

  // ── Raycasting ────────────────────────────────────────────────────────────

  const raycaster = new THREE.Raycaster();
  const mouse = new THREE.Vector2();

  renderer.domElement.addEventListener('click', (e) => {
    const rect = renderer.domElement.getBoundingClientRect();
    mouse.x =  ((e.clientX - rect.left) / rect.width)  * 2 - 1;
    mouse.y = -((e.clientY - rect.top)  / rect.height) * 2 + 1;
    raycaster.setFromCamera(mouse, camera);
    const hits = raycaster.intersectObjects(nodeMeshes);
    if (hits.length > 0) {
      renderInfoPanel(infoPanel, hits[0].object.userData.node, ctx);
    } else {
      infoPanel.style.display = 'none';
    }
  });

  // Pointer cursor on hover
  renderer.domElement.addEventListener('mousemove', (e) => {
    const rect = renderer.domElement.getBoundingClientRect();
    mouse.x =  ((e.clientX - rect.left) / rect.width)  * 2 - 1;
    mouse.y = -((e.clientY - rect.top)  / rect.height) * 2 + 1;
    raycaster.setFromCamera(mouse, camera);
    const hits = raycaster.intersectObjects(nodeMeshes);
    renderer.domElement.style.cursor = hits.length > 0 ? 'pointer' : 'default';
  });

  // ── Animation loop ────────────────────────────────────────────────────────

  const clock = new THREE.Clock();
  let frameId;

  function animate() {
    frameId = requestAnimationFrame(animate);
    const t = clock.getElapsedTime();

    nodeMeshes.forEach((mesh) => {
      if (mesh.userData.isActive) {
        // Gentle pulse: scale + emissive
        const pulse = Math.sin(t * 1.8 + mesh.position.x * 0.7) * 0.5 + 0.5;
        mesh.scale.setScalar(1 + pulse * 0.12);
        mesh.material.emissiveIntensity = mesh.userData.baseEmissive + pulse * 0.18;
      } else if (mesh.userData.isMastered) {
        // Slow shimmer for mastered
        mesh.material.emissiveIntensity = 0.4 + Math.sin(t * 0.6 + mesh.position.z) * 0.1;
      }
    });

    controls.update();
    renderer.render(scene, camera);
  }

  animate();

  // ── Resize ────────────────────────────────────────────────────────────────

  function onResize() {
    const W2 = container.clientWidth;
    const H2 = container.clientHeight;
    camera.aspect = W2 / H2;
    camera.updateProjectionMatrix();
    renderer.setSize(W2, H2);
  }
  window.addEventListener('resize', onResize);

  // ── Cleanup ───────────────────────────────────────────────────────────────

  // Store on container so router can call on unmount if needed
  container._cleanup = () => {
    cancelAnimationFrame(frameId);
    window.removeEventListener('resize', onResize);
    controls.dispose();
    renderer.dispose();
    sharedGeo.dispose();
    glowGeo.dispose();
    starGeo.dispose();
  };
}

