        ${node.progress_state ?? 'unknown'}
      </span>
    </div>
    <div style="display:flex;gap:8px">
      <button
        data-action="checkpoint"
        data-topic="${node.id}"
        style="flex:1;background:#4f9cf9;color:#fff;border:none;border-radius:5px;padding:7px 0;cursor:pointer;font-size:12px;font-weight:600">
        Checkpoint
      </button>
      <button
        data-action="check"
        data-topic="${node.id}"
        style="flex:1;background:#2d3148;color:#e2e8f0;border:none;border-radius:5px;padding:7px 0;cursor:pointer;font-size:12px">
        Knowledge Check
      </button>
    </div>
    <div style="margin-top:10px;padding-top:10px;border-top:1px solid #2d3148;text-align:right">
      <button data-action="close"
        style="background:none;border:none;color:#64748b;cursor:pointer;font-size:11px">
        ✕ close
      </button>
    </div>
  `;

  panel.querySelector('[data-action="checkpoint"]').addEventListener('click', () => {
    ctx.navigate(`checkpoint?topic_id=${node.id}`);
  });
  panel.querySelector('[data-action="check"]').addEventListener('click', () => {
    ctx.navigate(`knowledge-check?topic_id=${node.id}`);
  });
  panel.querySelector('[data-action="close"]').addEventListener('click', () => {
    panel.style.display = 'none';
  });
}

